import type { Question } from './types'
import {
  makeQuestionBank,
} from './base'

export function buildQuantQuestionCatalog(): Record<string, Question[]> {
  return {
    quant: makeQuestionBank('Quant Finance', [
      // Brain Teasers
      { id: 19001, chapter: 'Brain Teasers', title: 'Screwy Pirates', prompt: 'Five rational pirates must divide 100 gold coins. The senior pirate proposes a split. If 50% or more vote yes, it passes. Otherwise, the proposer is thrown overboard. What does the senior pirate propose?', correct: '98 to himself, 1 to pirate 3, 1 to pirate 5', wrong: [['100 to himself', 'He will be outvoted and thrown overboard.', 'He needs to buy just enough votes.'], ['20 to each', 'Rational pirates want to maximize their own gold, not be fair.', 'Consider the base cases with 2 or 3 pirates.'], ['99 to himself, 1 to pirate 2', 'Pirate 2 will vote no, hoping to get all 100 later.', 'Buy the votes of those who would get nothing otherwise.']] },
      { id: 19002, chapter: 'Brain Teasers', title: 'River Crossing', prompt: 'Four people take 1, 2, 5, and 10 minutes to cross a bridge. They have one flashlight. A maximum of two people can cross at once, moving at the slower person\'s pace. What is the minimum time for all to cross?', correct: '17 minutes', wrong: [['19 minutes', 'Sending the fastest person back every time is not optimal.', 'Group the two slowest people together.'], ['21 minutes', 'You can do better by pairing the 5 and 10 minute people.', 'Try to eliminate the 5 minute penalty entirely.'], ['16 minutes', 'You still need time to return the flashlight.', 'Don\'t forget the return trips.']] },
      { id: 19003, chapter: 'Brain Teasers', title: 'Burning Ropes', prompt: 'You have two ropes of varying thickness. Each takes exactly 60 minutes to burn completely. How can you measure exactly 45 minutes?', correct: 'Light both ends of rope 1 and one end of rope 2. When rope 1 finishes, light the other end of rope 2.', wrong: [['Light rope 1, wait for it to burn 3/4 of the way', 'The ropes burn unevenly, so length does not correspond to time.', 'You must use the entire burn time.'], ['Cut one rope into 4 equal pieces', 'Thickness varies, so a 1/4 piece doesn\'t take 15 minutes.', 'Use simultaneous burning from both ends.'], ['Light one end of both ropes, extinguish one after 15 mins', 'You have no way to know when 15 minutes has passed.', 'A rope lit from both ends burns in 30 minutes.']] },
      { id: 19004, chapter: 'Brain Teasers', title: 'Defective Ball', prompt: 'You have 12 identical-looking balls and a balance scale. One ball is heavier or lighter than the rest. What is the minimum number of weighings to find it?', correct: '3', wrong: [['4', 'You can do it in fewer weighings by dividing into 3 groups.', 'Weigh 4 against 4 first.'], ['2', 'Two weighings can only distinguish up to 9 balls.', 'Consider the information gained from each weighing (3 states).'], ['5', 'A binary search approach is too slow. Use all three states of the scale.', 'Divide into groups of 4.']] },
      { id: 19005, chapter: 'Brain Teasers', title: 'Trailing Zeros', prompt: 'How many trailing zeros are there in 100! (100 factorial)?', correct: '24', wrong: [['20', 'You forgot that some numbers contribute multiple factors of 5.', 'Count multiples of 25.'], ['10', 'Trailing zeros are determined by pairs of 2 and 5.', 'Count the number of times 5 divides into the sequence.'], ['21', 'Numbers like 25, 50, 75, and 100 provide an extra 5.', 'Include the powers of 5.']] },
      { id: 19006, chapter: 'Brain Teasers', title: 'Horse Race', prompt: 'You have 25 horses and a 5-lane track. What is the minimum number of races to find the top 3 fastest horses?', correct: '7', wrong: [['6', 'Six races only identifies the fastest horse of all.', 'You need a 7th race to find the 2nd and 3rd fastest.'], ['8', 'You can optimize the final race to only include the potential candidates.', 'The top horses from the slowest heats can be eliminated.'], ['10', 'You don\'t need a full round-robin tournament.', 'Use heats and a final championship race.']] },
      { id: 19007, chapter: 'Brain Teasers', title: 'Box Packing', prompt: 'Can you pack 53 bricks of dimensions 1x1x4 into a 6x6x6 box?', correct: 'No', wrong: [['Yes', 'Consider the volume and the coloring of the grid.', 'Use a 3D checkerboard coloring argument.'], ['Yes, but only if placed vertically', 'Orientation does not solve the fundamental constraint.', 'Think about how a 1x1x4 block intersects a 2x2x2 sub-grid.'], ['It is mathematically impossible to know', 'It can be proven impossible.', 'Consider sub-cubes of 2x2x2.']] },
      { id: 19008, chapter: 'Brain Teasers', title: 'Calendar Cubes', prompt: 'You have two cubes to display the day of the month (01-31). What digits must be on the two cubes?', correct: 'Cube 1: 0,1,2,3,4,5. Cube 2: 0,1,2,6,7,8 (using 6 as 9)', wrong: [['Cube 1: 0-5, Cube 2: 4-9', 'You need 0, 1, and 2 on both cubes to make 01-11, 22.', '0, 1, and 2 must be duplicated.'], ['It is impossible with only 12 faces', 'You can reuse one of the digits by flipping it upside down.', 'Think about the number 9.'], ['Cube 1: 0,1,2,3,4,6. Cube 2: 0,1,2,5,7,8', 'You need 0,1,2 on both. You are missing 9.', 'The 6 can double as a 9.']] },
      { id: 19009, chapter: 'Brain Teasers', title: 'Light Switches', prompt: 'You are outside a closed room with 3 light switches. Inside is 1 bulb. You can flip switches, but only enter the room once. How do you find the right switch?', correct: 'Turn on Switch 1 for 10 mins. Turn it off, turn on Switch 2, and enter. Feel for heat.', wrong: [['Flip them really fast', 'That doesn\'t give you enough information.', 'You need to use another physical property besides light.'], ['Turn on Switch 1 and 2, then go in', 'If it is on, you won\'t know if it is 1 or 2.', 'You need three distinct states for three switches.'], ['It is impossible', 'Use multiple senses.', 'Think about what a lightbulb does besides emit light.']] },
      { id: 19010, chapter: 'Brain Teasers', title: 'Quant Salary', prompt: '8 quants want to know their average salary without revealing their own. How?', correct: 'Quant 1 adds a random number to their salary and passes it. The last quant gives the total back. Quant 1 subtracts the random number and divides by 8.', wrong: [['They write it on paper anonymously', 'Handwriting could reveal identity.', 'Use a mathematical protocol.'], ['They whisper it to a 9th person', 'That requires trusting a 3rd party.', 'Use a cryptographic sum.'], ['It is impossible without a trusted mediator', 'You can use a secure multi-party computation trick.', 'Think about adding noise.']] },
      { id: 19011, chapter: 'Brain Teasers', title: 'Coin Piles', prompt: 'Blindfolded, you have 1000 coins: 980 tails, 20 heads. Split them into two piles with an equal number of heads.', correct: 'Take 20 coins to form a new pile. Flip all 20 coins in the new pile.', wrong: [['Split them 500/500 and hope', 'That relies on luck, not logic.', 'You must guarantee the outcome.'], ['Flip all 1000 coins', 'That just gives you 980 heads and 20 tails.', 'Create a smaller pile and flip it.'], ['Feel for the heads', 'The prompt says you are blindfolded and cannot feel the difference.', 'Use a mathematical operation.']] },
      { id: 19012, chapter: 'Brain Teasers', title: 'Mislabeled Bags', prompt: 'You have 3 bags: Apples, Oranges, and Mixed. ALL are mislabeled. You can pick one fruit from one bag. How do you fix the labels?', correct: 'Pick from the "Mixed" bag. If it is an apple, that bag is Apples. The "Oranges" bag must be Mixed, and "Apples" is Oranges.', wrong: [['Pick from "Apples"', 'If you pull an orange, the bag could be Oranges or Mixed.', 'Use the bag that gives the most information.'], ['You need to pick at least two fruits', 'One is enough if you pick from the right bag.', 'Since all labels are wrong, "Mixed" cannot be Mixed.'], ['Dump them all out', 'That violates the constraints.', 'Exploit the fact that ALL labels are incorrect.']] },
      { id: 19013, chapter: 'Brain Teasers', title: 'Missing Integers', prompt: 'An array has 98 distinct integers from 1 to 100. How do you efficiently find the missing two?', correct: 'Calculate the sum and sum of squares of the array. Compare with the expected sum and sum of squares of 1 to 100 to form two equations.', wrong: [['Sort the array and iterate', 'Sorting takes O(n log n), which is less efficient than O(n).', 'Use mathematical properties.'], ['Use a hash map', 'That requires O(n) extra space.', 'Can you do it in O(1) space?'], ['Calculate the product of all numbers', 'Products of 100 numbers will cause severe overflow issues.', 'Use addition and squares instead.']] },
      { id: 19014, chapter: 'Brain Teasers', title: 'Counterfeit Coins I', prompt: '10 bags of coins. One bag has fake coins weighing 9g (real ones are 10g). You have a digital scale and one weighing. Find the fake bag.', correct: 'Take 1 coin from bag 1, 2 from bag 2... up to 10 from bag 10. Weigh them. The difference from 550g identifies the bag.', wrong: [['Weigh one coin from each bag', 'They will all weigh 99g, giving no information.', 'You need to weight the bags differently.'], ['Weigh the bags against each other', 'It is a digital scale, not a balance scale.', 'Use a linear combination.'], ['It is impossible with one weighing', 'You can encode the bag number into the number of coins.', 'Triangular numbers.']] },
      { id: 19015, chapter: 'Brain Teasers', title: 'Glass Balls', prompt: 'You have 2 glass balls and a 100-story building. Find the lowest floor they break from in the minimum worst-case drops.', correct: '14 drops. Drop from 14, 27, 39... decreasing the gap by 1 each time.', wrong: [['10 drops, dropping every 10 floors', 'If it breaks at 100, you have to test 91-99, totaling 19 drops.', 'You want to minimize the worst-case, balancing both balls.'], ['50 drops, binary search', 'If the first ball breaks at 50, you have to test 1-49 one by one.', 'Binary search requires log2(N) balls, not just 2.'], ['100 drops, one by one', 'That is the safest but not the minimum worst-case.', 'Use the first ball to skip floors.']] },

      // Probability
      { id: 19101, chapter: 'Probability', title: 'Boy or Girl', prompt: 'A family has two children. One is a boy. What is the probability the other is a boy?', correct: '1/3', wrong: [['1/2', 'The sample space is BB, BG, GB. We eliminate GG.', 'Consider all combinations of two children.'], ['1/4', 'We already know one is a boy, so the probability is higher.', 'Update your sample space.'], ['0', 'They can have two boys.', 'Think BB, BG, GB.']] },
      { id: 19102, chapter: 'Probability', title: 'Russian Roulette', prompt: 'Two bullets are loaded into adjacent chambers of a 6-chamber revolver. The first player fires and survives. Should you spin the cylinder before your turn?', correct: 'Do not spin. The probability of dying is 1/4 if you don\'t spin, and 2/6 (1/3) if you do.', wrong: [['Spin it', 'Spinning resets the probability to 2/6.', 'You know the previous chamber was empty. What follows an empty chamber?'], ['It doesn\'t matter', 'The conditional probability changes because the bullets are adjacent.', 'Given chamber N is empty, what is the chance N+1 has a bullet?'], ['Shoot the ceiling', 'That is not an option in the game.', 'Compare 1/4 to 1/3.']] },
      { id: 19103, chapter: 'Probability', title: 'Aces', prompt: '52 cards are dealt to 4 players (13 each). What is the probability each player gets exactly one Ace?', correct: 'Approximately 10.5%. (39/51) * (26/50) * (13/49)', wrong: [['1/4', 'That is the expected value of aces per player, not the probability of the exact distribution.', 'Use conditional probability.'], ['(1/13)^4', 'The events are dependent. Dealing an ace affects the rest of the deck.', 'Think about placing the aces one by one into different hands.'], ['4!', 'That is a permutation, not a probability.', 'Calculate the chance the 2nd ace goes to a different pile, then the 3rd, etc.']] },
      { id: 19104, chapter: 'Probability', title: 'Gambler\'s Ruin', prompt: 'You have $1. You win $1 with p=0.5, lose $1 with p=0.5. You stop when you reach $100 or $0. What is the probability of reaching $100?', correct: '1/100', wrong: [['1/2', 'The game is symmetric, but the boundaries are not.', 'Your expected value is constant.'], ['1/50', 'You are starting very close to 0.', 'Use the martingale property: Expected wealth = initial wealth.'], ['It is certain you will go broke', 'While highly likely (99%), it is not certain.', 'E[Wealth] = 1 = P(win)*100 + P(lose)*0.']] },
      { id: 19105, chapter: 'Probability', title: 'N Points on a Circle', prompt: 'N points are drawn randomly on a circle. What is the probability they all lie within the same semicircle?', correct: 'N / 2^(N-1)', wrong: [['1 / 2^N', 'That is the probability they fall in a *specific* predefined semicircle.', 'The semicircle can start at any of the N points.'], ['N / 2^N', 'You must condition on the first point.', 'Any of the N points could be the "leading" point.'], ['1 / N!', 'This is a geometry/probability question, not just ordering.', 'Consider the arcs between points.']] },
      { id: 19106, chapter: 'Probability', title: 'Birthday Problem', prompt: 'How many people do you need in a room to have a >50% chance that two share a birthday?', correct: '23', wrong: [['183', 'That would be 50% of the days in a year, which is a different question.', 'Calculate the probability that NO ONE shares a birthday.'], ['365', 'With 365, it is almost 100%. 366 guarantees it.', 'The probabilities compound multiplicatively.'], ['50', 'At 50 people, the probability is actually 97%.', 'The curve rises very steeply.']] },
      { id: 19107, chapter: 'Probability', title: 'Drunk Passenger', prompt: '100 passengers board a plane. Passenger 1 is drunk and takes a random seat. Everyone else takes their assigned seat, or a random one if theirs is taken. What is the probability passenger 100 gets their own seat?', correct: '1/2', wrong: [['1/100', 'The sequence of displacements simplifies dramatically.', 'By the time passenger 100 boards, only seat 1 and seat 100 are left.'], ['99/100', 'The drunk passenger creates a chain reaction.', 'Consider a 2-passenger case, then 3-passenger.'], ['0', 'It is absolutely possible they get their seat.', 'Any displaced passenger effectively becomes the new "drunk" passenger.']] },
      { id: 19108, chapter: 'Probability', title: 'Connecting Noodles', prompt: 'A bowl has 100 noodles. You randomly tie ends together until no ends are left. What is the expected number of closed loops?', correct: 'Sum from k=1 to 100 of [1 / (2k - 1)]', wrong: [['50', 'You don\'t always form a loop when tying two ends.', 'You might tie a noodle to a different noodle.'], ['100', 'Tying ends reduces the number of loose ends.', 'Calculate the probability of forming a loop on the first tie.'], ['ln(100)', 'It is an approximation, but not the exact expected value.', 'Use an indicator variable for each step.']] },
      { id: 19109, chapter: 'Probability', title: 'Dice Game', prompt: 'You roll a die. For 4, 5, 6 you roll again and accumulate money. For 1, 2, 3 the game stops. What is your expected payoff?', correct: '$7', wrong: [['$3.50', 'That is the expected value of a single roll.', 'You have a 50% chance to roll again.'], ['$10.50', 'You are double counting some expectations.', 'Set up a recursive equation: E = 3.5 + 0.5 * E'], ['Infinity', 'The game ends eventually.', 'E = E[Roll] + P(Roll again) * E']] },
      { id: 19110, chapter: 'Probability', title: 'Card Game Ace', prompt: 'Cards are drawn from a 52-card deck. What is the expected number of cards drawn to see the first Ace?', correct: '10.6', wrong: [['13', 'The 4 aces divide the remaining 48 cards into 5 intervals.', 'Consider the spaces between the aces.'], ['26', 'That would be the expected wait for a specific card.', 'There are four targets.'], ['10', 'It is slightly higher than 48/5.', 'Expected cards = 1 + 48/5.']] },
      { id: 19111, chapter: 'Probability', title: 'Unfair Coin', prompt: 'You have 1000 coins. 999 are fair, 1 is double-headed. You pick one, toss it 10 times, and get 10 heads. What is the probability it is the fake coin?', correct: '1024 / 2023 (approx 50%)', wrong: [['1/1000', 'You must update your prior based on the 10 heads.', 'Use Bayes Theorem.'], ['99%', 'A fair coin getting 10 heads is rare (1/1024), but there are 999 fair coins.', 'P(Fake|10H) = P(10H|Fake)P(Fake) / P(10H)'], ['100%', 'A fair coin CAN flip 10 heads.', 'The evidence is strong, but the prior was very low.']] },
      { id: 19112, chapter: 'Probability', title: 'Fair from Unfair', prompt: 'You have a biased coin with unknown probability p of heads. How do you simulate a fair coin toss?', correct: 'Toss twice. If HT, call it Heads. If TH, call it Tails. If HH or TT, repeat.', wrong: [['Toss it 100 times and take the average', 'That gives you an estimate of p, not a single fair binary event.', 'You need exactly 50/50 probability.'], ['Toss it once and flip the result', 'That just gives you 1-p, which is still biased.', 'Find two events that have the exact same probability.'], ['It is mathematically impossible', 'Von Neumann proved it is possible.', 'P(HT) = p(1-p) and P(TH) = (1-p)p.']] },
      { id: 19113, chapter: 'Probability', title: 'Coupon Collector', prompt: 'Cereal boxes contain one of N distinct coupons uniformly. What is the expected number of boxes to collect all N?', correct: 'N * Sum(1/i) for i=1 to N', wrong: [['N', 'You will get duplicates.', 'The last few coupons take a long time to find.'], ['N^2', 'That overestimates the time.', 'Use the geometric distribution for each new coupon.'], ['N * ln(N)', 'This is a good approximation, but not the exact answer.', 'Expected time = N/N + N/(N-1) + ... + N/1']] },
      { id: 19114, chapter: 'Probability', title: 'Random Ants', prompt: '500 ants are placed randomly on a 1-meter stick. They walk at 1 meter/minute. When they collide, they reverse direction. Expected time for all to fall off?', correct: 'Maximum of 500 independent uniform[0,1] variables, which is 500/501 minutes.', wrong: [['250 minutes', 'The ants don\'t get stuck.', 'Think about what actually happens during a collision.'], ['It depends on their starting positions', 'You are asked for the expected time over all random starts.', 'A collision is physically identical to the ants passing through each other.'], ['1 minute', 'That is the absolute maximum possible time, not the expected time.', 'Expected value of the maximum of N uniform random variables.']] },
      { id: 19115, chapter: 'Probability', title: 'Expected Max', prompt: 'X and Y are independent uniform(0,1) random variables. What is the expected value of max(X, Y)?', correct: '2/3', wrong: [['1/2', 'The maximum of two variables will be skewed higher than the mean of one.', 'Integrate the CDF of the maximum.'], ['3/4', 'That is the expected value for a different distribution.', 'P(max < z) = P(X < z)P(Y < z) = z^2.'], ['1', 'It cannot be 1 unless both are always 1.', 'The density is 2z. Expected value is integral of z * 2z.']] },

      // Calculus & Linear Algebra
      { id: 19201, chapter: 'Calculus', title: 'e^pi vs pi^e', prompt: 'Without a calculator, which is larger: e^pi or pi^e?', correct: 'e^pi', wrong: [['pi^e', 'Use calculus to find the maximum of f(x) = (ln x)/x.', 'Take the natural log of both sides.'], ['They are exactly equal', 'e and pi are different transcendental numbers.', 'Look at the function x^(1/x).'], ['It is impossible to know without expanding the series', 'You can prove it by analyzing the derivative of ln(x)/x.', 'The maximum occurs at x=e.']] },
      { id: 19202, chapter: 'Linear Algebra', title: 'Positive Definite', prompt: 'If A is a symmetric positive definite matrix, what is true about its eigenvalues?', correct: 'All eigenvalues are strictly greater than 0', wrong: [['They are all zero', 'That would be a zero matrix.', 'x^T A x > 0 for all non-zero x.'], ['They can be negative', 'Positive definite means strictly positive curvature in all directions.', 'If an eigenvalue was negative, x^T A x could be negative.'], ['They are complex numbers', 'A symmetric matrix always has real eigenvalues.', 'Real and strictly positive.']] },
      { id: 19203, chapter: 'Calculus', title: 'Taylor Series', prompt: 'What is the Taylor series expansion of e^x around x=0?', correct: '1 + x + x^2/2! + x^3/3! + ...', wrong: [['1 - x + x^2 - x^3', 'That is for 1/(1+x).', 'Derivatives of e^x are all e^x.'], ['x - x^3/3! + x^5/5!', 'That is the series for sin(x).', 'e^x contains all powers of x.'], ['1 + 2x + 3x^2', 'That is for 1/(1-x)^2.', 'Divide by factorials.']] },
      { id: 19204, chapter: 'Linear Algebra', title: 'Trace and Determinant', prompt: 'For an NxN matrix A, how do the eigenvalues relate to the trace and determinant?', correct: 'Trace = sum of eigenvalues, Determinant = product of eigenvalues', wrong: [['Trace = product, Determinant = sum', 'You have it backwards.', 'Look at the characteristic polynomial.'], ['Trace = largest eigenvalue', 'Trace is the sum of the diagonal elements.', 'It incorporates all eigenvalues.'], ['Determinant = trace squared', 'They are fundamentally different combinations.', 'Product of roots vs sum of roots.']] },
      { id: 19205, chapter: 'Calculus', title: 'L\'Hospital\'s Rule', prompt: 'Evaluate the limit as x approaches 0 of sin(x) / x.', correct: '1', wrong: [['0', 'sin(0) is 0, but you must look at the ratio.', 'Use L\'Hospital\'s rule or Taylor expansion.'], ['Infinity', 'The function is well-behaved near 0.', 'Derivative of sin(x) is cos(x).'], ['Undefined', 'The limit exists.', 'cos(0) / 1 = 1.']] },

      // Stochastic Calculus & Options
      { id: 19301, chapter: 'Finance', title: 'Put-Call Parity', prompt: 'What is the put-call parity formula for a European option on a non-dividend paying stock?', correct: 'C - P = S - K * e^(-rt)', wrong: [['C + P = S + K', 'You must account for the time value of money.', 'Consider a portfolio of long call, short put.'], ['C = P', 'Only true if the forward price equals the strike.', 'A call and put have different payoff profiles.'], ['C - P = K - S', 'You reversed the underlying and the strike.', 'Long call, short put mimics a forward contract.']] },
      { id: 19302, chapter: 'Stochastic', title: 'Ito\'s Lemma', prompt: 'If dS = mu*S*dt + sigma*S*dW, what is the process for d(ln S)?', correct: 'd(ln S) = (mu - sigma^2/2)dt + sigma*dW', wrong: [['d(ln S) = mu*dt + sigma*dW', 'Standard calculus does not apply to stochastic processes.', 'You must use Ito\'s Lemma and include the 1/2 * f\'\'(S) * (dS)^2 term.'], ['d(ln S) = sigma^2 dt', 'You are missing the drift and diffusion terms.', 'Apply f(S) = ln(S).'], ['d(ln S) = (mu + sigma^2/2)dt', 'The convexity adjustment reduces the drift.', 'The second derivative of ln(S) is -1/S^2.']] },
      { id: 19303, chapter: 'Finance', title: 'American Call Exercise', prompt: 'Why is it never optimal to exercise an American call option early on a non-dividend paying stock?', correct: 'The option\'s time value is always positive; you can sell it for more than its intrinsic value.', wrong: [['Because the stock price might go down', 'Even if it goes down, early exercise is suboptimal.', 'Exercising early destroys the insurance value (the put).'], ['It is optimal if the stock goes up 100%', 'No, the market price of the call will reflect that gain plus time value.', 'You lose the time value of money on the strike price K.'], ['American options cannot be exercised early', 'They can, but it is mathematically suboptimal for calls.', 'Compare selling the option vs exercising it.']] },
      { id: 19304, chapter: 'Stochastic', title: 'Brownian Motion Covariance', prompt: 'Let W(t) be a standard Brownian motion. What is the covariance between W(s) and W(t) for s < t?', correct: 's', wrong: [['t', 'The covariance is determined by the earlier time.', 'Cov(W(s), W(t)) = Cov(W(s), W(s) + (W(t)-W(s))).'], ['t - s', 'That is the variance of the increment.', 'Increments are independent.'], ['0', 'They are highly correlated because W(t) includes W(s).', 'Use the independence of increments.']] },
      { id: 19305, chapter: 'Finance', title: 'Delta of ATM Call', prompt: 'What is the approximate Delta of an at-the-money (S=K) European call option near maturity?', correct: '0.5', wrong: [['1.0', 'That is the delta of a deep in-the-money call.', 'There is roughly a 50/50 chance it finishes in the money.'], ['0.0', 'That is for a deep out-of-the-money option.', 'N(d1) approximates to N(0).'], ['-0.5', 'Call deltas are strictly positive.', 'As stock goes up, call goes up.']] },
      { id: 19306, chapter: 'Finance', title: 'Gamma near Maturity', prompt: 'What happens to the Gamma of an at-the-money option as it approaches maturity?', correct: 'It approaches infinity (becomes a Dirac delta function).', wrong: [['It goes to zero', 'Gamma goes to zero for ITM and OTM options, but explodes for ATM.', 'The Delta changes violently from 0 to 1 as it crosses the strike.'], ['It remains constant', 'Time to maturity is in the denominator of the Gamma formula.', 'Gamma is highest when uncertainty is compressed into a short time.'], ['It becomes negative', 'Vanilla option Gamma is always positive.', 'Long options have positive convexity.']] },
      { id: 19307, chapter: 'Stochastic', title: 'Martingale Definition', prompt: 'What is the defining mathematical property of a martingale process M(t)?', correct: 'E[M(t) | F(s)] = M(s) for all s < t', wrong: [['The variance is constant', 'Variance usually grows over time (e.g., Brownian motion).', 'It relates to the expected value.'], ['The process is mean-reverting', 'Martingales have no drift.', 'The best prediction of the future is the present.'], ['It cannot be negative', 'Brownian motion is a martingale and goes negative.', 'It is a fair game concept.']] },
      { id: 19308, chapter: 'Finance', title: 'Black-Scholes Assumptions', prompt: 'Which of the following is NOT an assumption of the standard Black-Scholes model?', correct: 'Volatility is stochastic and changing', wrong: [['Trading is continuous', 'This is a core assumption to allow perfect hedging.', 'BSM assumes perfect replication.'], ['Interest rates are constant', 'BSM assumes a constant, known risk-free rate.', 'Only the stock price is stochastic.'], ['No transaction costs', 'BSM assumes frictionless markets.', 'Hedging requires infinite trading.']] },
      { id: 19309, chapter: 'Stochastic', title: 'Quadratic Variation', prompt: 'What is the quadratic variation of standard Brownian motion W(t) over the interval [0, t]?', correct: 't', wrong: [['0', 'Standard smooth functions have zero quadratic variation, but Brownian paths are jagged.', 'dt * dt = 0, but dW * dW = dt.'], ['t^2', 'That would be the variance of t*W(1).', 'It grows linearly with time.'], ['Infinity', 'The total variation is infinity, but quadratic variation is finite.', 'Sum of (dW)^2 converges to t.']] },
      { id: 19310, chapter: 'Finance', title: 'Theta', prompt: 'For a long vanilla option portfolio, what is the typical sign of Theta (time decay)?', correct: 'Negative', wrong: [['Positive', 'Options lose value as time passes, assuming everything else is constant.', 'Time value erodes.'], ['Zero', 'Only true at exactly maturity.', 'You pay for the option to hold it.'], ['It depends on the stock price', 'For vanilla options, Theta is almost always negative (except deep ITM European puts).', 'Time works against the option holder.']] },

      // Additional Applied Questions
      { id: 19401, chapter: 'Finance', title: 'Risk-Neutral Measure', prompt: 'Under the risk-neutral measure, what is the expected return of a stock?', correct: 'The risk-free interest rate (r)', wrong: [['The real-world drift (mu)', 'We change the measure specifically to remove risk preferences.', 'All assets earn the risk-free rate.'], ['Zero', 'Investors still require the time value of money.', 'Discounting by the risk-free rate makes it a martingale.'], ['The volatility (sigma)', 'Volatility determines the spread, not the mean return.', 'Return must equal the cost of borrowing.']] },
      { id: 19402, chapter: 'Finance', title: 'Straddle Payoff', prompt: 'A long straddle consists of buying a call and a put with the same strike K. When is this strategy profitable?', correct: 'When the stock price moves significantly in EITHER direction', wrong: [['When the stock price stays exactly at K', 'That is the point of maximum loss (you lose both premiums).', 'You are long volatility.'], ['Only when the stock goes up', 'The put covers the downside.', 'It is a non-directional bet.'], ['When implied volatility drops', 'Long options lose value when IV drops.', 'You want explosive movement.']] },
      { id: 19403, chapter: 'Stochastic', title: 'Geometric Brownian Motion', prompt: 'Why is Geometric Brownian Motion (GBM) used to model stock prices instead of standard Brownian Motion?', correct: 'GBM ensures stock prices never become negative and returns are proportional to price.', wrong: [['GBM has zero variance', 'It has variance proportional to S^2.', 'Standard BM can cross zero.'], ['GBM is completely predictable', 'It is still a stochastic process.', 'Stock prices are bounded by limited liability.'], ['Standard BM is too hard to calculate', 'Standard BM is actually easier to calculate.', 'Think about the boundaries of a stock price.']] },
      { id: 19404, chapter: 'Brain Teasers', title: '100th Digit', prompt: 'What is the 100th digit to the right of the decimal point for (1 + sqrt(2))^3000 ?', correct: '9', wrong: [['0', 'Consider the conjugate (1 - sqrt(2))^3000.', 'The sum of the two terms is always an integer.'], ['5', 'The conjugate term is incredibly small.', '(1 - sqrt(2)) is between -1 and 0.'], ['2', 'The expression is extremely close to an integer.', 'The integer part is slightly less than the total.']] },
      { id: 19405, chapter: 'Probability', title: 'Expected Value of Dice', prompt: 'You roll two standard dice. What is the expected value of their sum?', correct: '7', wrong: [['6', 'The minimum is 2, maximum is 12.', 'E[X+Y] = E[X] + E[Y].'], ['8', '7 is the most common roll.', 'E[X] = 3.5'], ['12', 'That is the maximum, not the average.', '3.5 + 3.5 = ?']] },
      { id: 19406, chapter: 'Brain Teasers', title: 'Ants on a Square', prompt: 'There are 51 ants on a square with side length of 1. If you have a glass with a radius of 1/7, can you put your glass at a position on the square to guarantee that the glass encompasses at least 3 ants?', correct: 'Yes, separate the square into 25 smaller areas of 1/5 x 1/5. By Pigeon Hole Principle, one area has at least 3 ants. A 1/7 radius circle covers a 1/5 square.', wrong: [['No', 'Consider the Pigeon Hole Principle.', 'Divide the square into 25 smaller regions.'], ['Yes, but only if the radius is at least 1/5', 'The diagonal of a 1/5 square is sqrt(2)/5, which is less than 2/7.', 'Calculate the circumcircle of a 1/5 square.'], ['It is impossible to guarantee', 'You have 51 ants and can create 25 regions.', '51 = 25 * 2 + 1']] },
      { id: 19407, chapter: 'Brain Teasers', title: 'Counterfeit Coins II', prompt: 'There are 5 bags with 100 coins in each bag. A coin can weigh 9g, 10g or 11g. Each bag contains coins of equal weight, but we do not know what type. How many times do you need to use a digital scale to determine the type for each bag?', correct: '1 time. Take 1, 3, 9, 27, and 81 coins from bags 1 to 5 respectively.', wrong: [['5 times', 'You can weigh coins from multiple bags together.', 'Use powers of 3.'], ['2 times', 'With 3 possible weights for 5 bags, there are 3^5 = 243 combinations.', 'One weighing can give enough information if coefficients grow fast enough.'], ['3 times', 'You can encode the combinations in base-3.', 'Use 1, 3, 9... coins.']] },
      { id: 19408, chapter: 'Brain Teasers', title: 'Handshakes', prompt: 'At a party with 26 people, random handshaking occurs. Can you guarantee there are at least two people who shook hands with exactly the same number of people?', correct: 'Yes. Each person shakes 0 to 25 hands, but 0 and 25 cannot happen simultaneously. So there are 25 possible handshakes for 26 people.', wrong: [['No', 'Think about the possible number of handshakes someone can have.', 'Use the Pigeon Hole Principle.'], ['Only if everyone shakes hands with everyone', 'It holds for any configuration of handshakes.', 'What is the maximum and minimum number of handshakes?'], ['Yes, exactly 3 people', 'You can only guarantee at least two.', '26 pigeons, 25 holes.']] },
      { id: 19409, chapter: 'Brain Teasers', title: 'Irrational Root', prompt: 'When proving that the square root of 2 is irrational by contradiction (assuming it equals m/n for integers m,n with no common factors), what is the key contradiction reached?', correct: 'Both m and n must be even numbers, contradicting that they have no common factors.', wrong: [['m and n must be equal', 'm^2 = 2n^2 does not imply m=n.', 'Focus on the parity of m and n.'], ['m^2 must be odd', 'Since m^2 = 2n^2, m^2 is clearly even.', 'What does m^2 being even say about m?'], ['The fraction is not simplified', 'The starting assumption is that it IS simplified.', 'Where does the math lead?']] },
      { id: 19410, chapter: 'Calculus', title: 'Derivative of Nested Log', prompt: 'What is the derivative of y = ln(ln x)?', correct: '1 / (x * ln x)', wrong: [['1 / ln x', 'You forgot the chain rule.', 'Apply d(ln u)/dx = (1/u) * du/dx'], ['1 / (x^2)', 'The inner function is ln x, not x^2.', 'u = ln x'], ['ln x / x', 'The derivative of ln u is 1/u, not u.', 'd(ln(ln x))/dx = 1/(ln x) * d(ln x)/dx']] },

      // Batch 1: Logic & Brain Teasers
      { id: 19016, chapter: 'Brain Teasers', title: 'Door to Offer', prompt: 'A truth-teller guards the door to the exit; a liar guards the door to a job offer. You don\'t know which is which. What one question can you ask one guard to find the door to the offer?', correct: 'What door would the other guard say is the door to the offer?', wrong: [['Which door is the offer?', 'You won\'t know if you\'re talking to the liar or the truth-teller.', 'A single question must neutralize the lie.'], ['Are you the truth-teller?', 'Both will say "Yes".', 'You need to link the two guards together.'], ['Is this door the exit?', 'You only get one question and one guard.', 'Use the double-negative property of logic.']] },
      { id: 19017, chapter: 'Brain Teasers', title: 'Message Delivery', prompt: 'You want to send a secure message to a friend in a box. You both have multiple padlocks but no shared keys. How can you deliver the message without a key ever being sent?', correct: 'Lock the box, send it. Friend adds their lock and sends it back. You remove your lock and send it back.', wrong: [['Pick the lock', 'The prompt assumes high-security padlocks.', 'Think about commutative locking operations.'], ['Send the key in a separate box', 'The separate box would also need a lock.', 'Keys are never safe in transit.'], ['Hide the key inside the box', 'The friend needs the key to open the box to get the key.', 'Use multiple layers of locks.']] },
      { id: 19018, chapter: 'Brain Teasers', title: 'Last Ball', prompt: 'A bag has 20 blue and 14 red balls. You take two out. If same color, add a blue ball. If different, add a red ball. What is the color of the last ball?', correct: 'Blue', wrong: [['Red', 'Red balls are always removed in pairs (or stay same). Their parity is invariant.', 'Look at how the number of red balls changes.'], ['It is random', 'The parity of the red balls is a deterministic invariant.', 'Check if the starting number of red balls is even or odd.'], ['Purple', 'That is not a color in the bag.', 'Logic before color theory.']] },
      { id: 19019, chapter: 'Brain Teasers', title: 'Wise Men', prompt: '50 wise men are in separate rooms. A sultan calls them one by one to a room with a glass. They can flip it or do nothing. When one correctly says everyone has been called, they are free. What is the strategy?', correct: 'One "spokesman" always flips the glass down. The others flip it up only once.', wrong: [['They all count their own visits', 'They don\'t know when others are called.', 'They need a shared state (the glass).'], ['They use a secret signal in the hallway', 'They are in separate rooms and cannot communicate.', 'The glass is the only communication channel.'], ['It is impossible', 'With a spokesman to tally the flips, it is possible.', 'The glass has 2 states.']] },
      { id: 19020, chapter: 'Brain Teasers', title: 'Clock Pieces', prompt: 'A clock face breaks into 3 pieces. The sum of the numbers on each piece is the same. What is the sum of each piece?', correct: '26', wrong: [['24', 'The total sum of 1-12 is 78. 78 / 3 = 26.', 'Sum the integers 1 through 12 first.'], ['39', 'That would be for 2 pieces.', '78 / 2 = 39.'], ['13', 'That would be for 6 pieces.', '78 / 6 = 13.']] },
      { id: 19021, chapter: 'Brain Teasers', title: 'Matching Socks', prompt: 'A drawer has 10 black and 10 white socks. What is the minimum number of socks you must pull out to guarantee a matching pair?', correct: '3', wrong: [['2', 'You could pull one black and one white.', 'Pigeonhole Principle: n+1 items for n colors.'], ['11', 'That guarantees you have a specific color, but not just ANY pair.', 'You only need a pair of the same color.'], ['21', 'That is the total number of socks plus one.', 'There are only 2 colors.']] },
      { id: 19022, chapter: 'Brain Teasers', title: 'Meeting People', prompt: 'In a group of 6 people, can you guarantee that either 3 people know each other or 3 people are strangers?', correct: 'Yes, this is a result of Ramsey Theory (R(3,3)=6).', wrong: [['No', 'In any group of 6, the property must hold.', 'Consider the connections from one person to the other 5.'], ['Only if the group is larger than 10', '6 is the minimum number for this property.', '3 vs 3 in a group of 6.'], ['It depends on their social skills', 'This is a graph theory property, not a social one.', 'Think of people as nodes and relationships as edges.']] },
      { id: 19023, chapter: 'Brain Teasers', title: 'Prisoner Problem', prompt: '100 prisoners are assigned numbers 1-100. They enter a room with 100 boxes containing random numbers. Each can open 50 boxes. They all survive if everyone finds their own number. Strategy?', correct: 'Each prisoner follows the "cycle" starting with the box labeled with their own number.', wrong: [['Open 50 random boxes', 'The probability of success is (1/2)^100, which is near zero.', 'They need to exploit the permutation structure.'], ['Communicate through the boxes', 'They cannot leave anything in the boxes.', 'They enter one by one.'], ['It is impossible to guarantee better than 1%', 'The cycle strategy gives a survival probability of ~30%.', 'Permutations consist of disjoint cycles.']] },
      { id: 19024, chapter: 'Brain Teasers', title: 'Division by 9', prompt: 'A number is divisible by 9 if and only if:', correct: 'The sum of its digits is divisible by 9.', wrong: [['It ends in 9', '19 is not divisible by 9.', 'Check the modular arithmetic of 10 mod 9.'], ['It is even and ends in 3', '23 is not divisible by 9.', '10^n is congruent to 1 mod 9.'], ['The last two digits are divisible by 9', 'That is the rule for 4 (last two) or 8 (last three).', 'Sum of digits is the key.']] },
      { id: 19025, chapter: 'Brain Teasers', title: 'Chameleon Colors', prompt: 'On an island there are 13 red, 15 green, and 17 blue chameleons. When two of different colors meet, they both change to the third color. Can they all become one color?', correct: 'No, because the differences between the counts modulo 3 are invariant.', wrong: [['Yes', 'Check the remainders when dividing the counts by 3.', '13 mod 3 = 1, 15 mod 3 = 0, 17 mod 3 = 2.'], ['Yes, but only if they meet in a specific order', 'The modular invariants prevent this regardless of order.', 'To reach (45, 0, 0), all remainders must be the same.'], ['Only if more chameleons are born', 'The question assumes a closed population.', 'Look at the values mod 3.']] },
      { id: 19026, chapter: 'Brain Teasers', title: 'Coin Split', prompt: 'You have n coins in a pile. You split a pile into two piles of size x and y, and write down the product x*y. You repeat until all piles are size 1. What is the sum of products?', correct: 'n(n-1) / 2', wrong: [['n^2', 'The sum is related to the number of pairs.', 'Think about the number of handshakes among n people.'], ['n!', 'That is for permutations, not a sum of products.', 'Try n=2, 3, 4.'], ['It depends on the splitting sequence', 'The sum is invariant to the order of splits.', 'This is a property of trees.']] },
      { id: 19027, chapter: 'Brain Teasers', title: 'Chocolate Bar', prompt: 'You have a 6x8 chocolate bar. What is the minimum number of breaks to separate it into 48 1x1 pieces? (A break is along a single straight line).', correct: '47', wrong: [['48', 'You start with 1 piece and end with 48. Each break adds exactly one piece.', 'n-1 breaks for n pieces.'], ['14', 'You cannot break multiple pieces at once.', 'Each break increases the count of pieces by one.'], ['24', 'That would only be enough if you could stack pieces.', 'Straight line breaks only.']] },
      { id: 19028, chapter: 'Brain Teasers', title: 'Race Track', prompt: 'N gas cans are on a circular track. Total gas is enough for one lap. Can you always find a starting point to complete the lap?', correct: 'Yes, by induction or by finding the point of minimum cumulative gas.', wrong: [['No', 'It is always possible.', 'Think about the net gas at each point.'], ['Only if N is even', 'The number of cans does not matter.', 'The total gas is the constraint.'], ['Only if the cans are spaced equally', 'Random placement is allowed.', 'Pick the "bottom" of the potential energy curve.']] },
      { id: 19029, chapter: 'Brain Teasers', title: 'Rainbow Hats', prompt: '7 prisoners have hats of 7 possible colors. They see all but their own. They must guess their own color simultaneously. If one is right, they are free. Strategy?', correct: 'Assign colors 0-6. Prisoner i guesses the color that makes the sum of all colors congruent to i (mod 7).', wrong: [['All guess the same color', 'If that color isn\'t present, they all fail.', 'They need to cover all possible remainders.'], ['Each guesses a different color', 'That doesn\'t account for what they see on others.', 'The sum mod 7 is the key.'], ['Guess based on the majority color', 'The executioner can choose colors to defeat this.', 'They need a deterministic coverage strategy.']] },
      { id: 19030, chapter: 'Brain Teasers', title: 'Staircase Problem', prompt: 'How many ways are there to climb 10 stairs if you can take 1 or 2 steps at a time?', correct: '89 (the 11th Fibonacci number)', wrong: [['10', 'There are many combinations of 1 and 2.', 'This is a recurrence relation: f(n) = f(n-1) + f(n-2).'], ['1024', 'That would be 2^10, but the total steps must sum to 10.', 'Check small cases: n=1, 2, 3.'], ['55', 'That is the 10th Fibonacci number.', 'f(1)=1, f(2)=2.']] },

      // Batch 1: Probability
      { id: 19116, chapter: 'Probability', title: 'Hopping Rabbit', prompt: 'A rabbit starts at 0 and hops 1 or 2 units forward with equal probability. What is the probability it ever lands on 10?', correct: '[2 + (-1/2)^10] / 3', wrong: [['1/2', 'The probability is slightly higher than 1/2.', 'P(n) = 0.5 * P(n-1) + 0.5 * P(n-2).'], ['2/3', 'That is the limit as n goes to infinity.', 'The characteristic equation is r^2 - 0.5r - 0.5 = 0.'], ['1', 'It might skip 10 by hopping from 9 to 11.', 'The rabbit is not guaranteed to land on every number.']] },
      { id: 19117, chapter: 'Probability', title: 'Chess Tournament', prompt: '8 players in a knockout tournament. Player 1 is best, Player 2 is second best. What is the probability they meet in the final?', correct: '4/7', wrong: [['1/2', 'They meet if they are in different halves of the bracket.', 'There are 7 other slots for player 2.'], ['1/7', 'That is the chance they meet in the first round.', 'They can meet in any round, but the final requires specific positioning.'], ['1/8', 'The bracket structure affects the outcome.', '4 slots are in the other half of the bracket.']] },
      { id: 19118, chapter: 'Probability', title: 'Application Letters', prompt: 'n letters are sent to n addresses. What is the probability that NO letter reaches the correct address as n goes to infinity?', correct: '1/e (approx 36.8%)', wrong: [['0', 'It is quite likely that everything is wrong.', 'This is the problem of derangements.'], ['1/2', 'The number of derangements is closer to n! / e.', 'Check the inclusion-exclusion principle.'], ['1/n', 'The probability converges to a constant, not zero.', 'Derangement formula: !n / n!']] },
      { id: 19119, chapter: 'Probability', title: 'All-Girl World', prompt: 'In a world where families stop having children as soon as they have a girl, what is the expected ratio of girls to boys in the population?', correct: '1:1', wrong: [['More girls', 'Each family has exactly one girl, but some have many boys.', 'The probability of a boy or girl at each birth is 1/2.'], ['More boys', 'Actually, the total expected number of boys and girls is equal.', 'E[Girls] = 1, E[Boys] = 1/2 + 1/4 + 1/8... = 1.'], ['2:1', 'The stopping rule does not change the birth probabilities.', 'This is a common intuition trap.']] },
      { id: 19120, chapter: 'Probability', title: 'Dart Game', prompt: 'You throw n darts. Each is further from the center than the first. If you throw one more, what is the probability it is also further than the first?', correct: 'n / (n+1)', wrong: [['1/2', 'The first dart being the best so far is a strong condition.', 'By symmetry, any of the n+1 darts is equally likely to be the best.'], ['1/n', 'That would be the chance it is the BEST dart.', 'We want the chance it is NOT the best.'], ['(n-1)/n', 'The total number of darts is n+1.', 'n out of n+1 positions are worse than the best.']] },
      { id: 19121, chapter: 'Probability', title: 'Birthday Line', prompt: 'A theater gives a free ticket to the first person in line with the same birthday as someone already in line. What position should you take to maximize your win?', correct: '20', wrong: [['23', 'That is for a 50% chance of a match in a group, not the individual win chance.', 'P(n) = P(n-1 people different) * (n-1)/365.'], ['1', 'The first person has a 0% chance of matching someone before them.', 'You need some people in front to have a match.'], ['366', 'By then, someone else will almost certainly have won.', 'The optimal point is where the increase in match probability meets the decrease in "no previous match" probability.']] },
      { id: 19122, chapter: 'Probability', title: 'Dice Order', prompt: 'You throw 3 dice. What is the probability the values are in strictly increasing order?', correct: '5 / 54', wrong: [['1/6', 'That is the chance of a specific order if all 3 are different.', 'You must first have 3 different numbers.'], ['1/216', 'That is for a specific sequence like 1, 2, 3.', 'There are many increasing sequences like 1, 2, 4 or 2, 3, 5.'], ['20/216', '6C3 / 216 = 20 / 216 = 5 / 54.', 'Select 3 distinct numbers from 6, then only 1 order works.']] },
      { id: 19123, chapter: 'Probability', title: 'Monty Hall', prompt: '3 doors, 1 car, 2 goats. You pick a door. Monty opens a door with a goat. Should you switch?', correct: 'Yes, switching doubles your win probability from 1/3 to 2/3.', wrong: [['It doesn\'t matter', 'There are 2 doors left, but they are not equally likely.', 'Monty\'s action provides information.'], ['No, keep your original choice', 'Your original door only has a 1/3 chance.', 'Switching wins if your original pick was a goat (2/3).'], ['Only if you like goats', 'The goal is to win the car.', 'Think about the 100-door version.']] },
      { id: 19124, chapter: 'Probability', title: 'Amoeba Population', prompt: 'An amoeba can die, stay same, split into 2, or split into 3 with equal probability. What is the probability the population dies out?', correct: 'sqrt(2) - 1 (approx 0.414)', wrong: [['1/4', 'The death of offspring must also be accounted for.', 'Solve P = 1/4 + 1/4*P + 1/4*P^2 + 1/4*P^3.'], ['1/2', 'That is for a different set of probabilities.', 'The root must be between 0 and 1.'], ['0', 'Populations can always die out.', 'Check the roots of the cubic equation.']] },
      { id: 19125, chapter: 'Probability', title: 'Candies in a Jar', prompt: 'A jar has 10 red, 20 blue, and 30 green candies. Probability that at least one blue and one green are left when all red are gone?', correct: '7/12', wrong: [['1/2', 'The larger counts of blue and green make it more likely.', 'P = 1 - P(Blue gone first) - P(Green gone first).'], ['1/3', 'Relative order matters, not just absolute counts.', 'Consider the last candy among Red and Blue, and Red and Green.'], ['11/12', 'The red candies will likely be exhausted before the others.', 'Use the relative ordering of the colors.']] },

      // Batch 2: More Probability
      { id: 19126, chapter: 'Probability', title: 'Basketball Scores', prompt: 'In a basketball game, Team A has scored n points and Team B has scored m points (n > m). What is the probability Team A was always leading?', correct: '(n - m) / (n + m)', wrong: [['1/2', 'It depends on the score difference.', 'This is the Reflection Principle applied to voting/scores.'], ['n / (n+m)', 'That is the probability they lead at the very end.', 'We want they lead AT ALL TIMES.'], ['(n-m)/n', 'The total number of paths is related to n+m.', 'Bertrand\'s Ballot Theorem.']] },
      { id: 19127, chapter: 'Probability', title: 'Cars on Road', prompt: 'Cars enter a road at a Poisson rate lambda. You see no cars for 10 minutes. What is the probability you see a car in the next 1 minute?', correct: '1 - e^(-lambda)', wrong: [['1/10', 'Poisson processes are memoryless.', 'P(T > t+s | T > t) = P(T > s).'], ['1/lambda', 'That is the expected time, not the probability.', 'P(X > 0) for X ~ Poisson(lambda).'], ['It depends on the 10 minutes', 'Memorylessness means the past does not affect the future.', 'The rate remains lambda.']] },
      { id: 19128, chapter: 'Probability', title: 'Meeting Probability', prompt: 'Two people arrive at a park at random times between 12:00 and 1:00. Each stays for 15 minutes. What is the probability they meet?', correct: '7/16', wrong: [['1/4', 'The meeting region is larger than just 1/4 of the square.', 'Area = 1 - (3/4)^2.'], ['1/2', 'That would be if they stayed for 30 minutes.', 'Draw a 1x1 square and the region |x-y| < 0.25.'], ['9/16', 'That is the probability they DO NOT meet if they arrive in a specific order.', '1 - (1 - 0.25)^2 = 1 - 0.5625 = 0.4375 = 7/16.']] },
      { id: 19129, chapter: 'Probability', title: 'Triangle Probability', prompt: 'A stick of length 1 is broken at two random points. What is the probability the 3 pieces can form a triangle?', correct: '1/4', wrong: [['1/2', 'The conditions for a triangle are strict (sum of any two > third).', 'Check the region in the unit square.'], ['1/3', 'There are three segments, but the geometry gives 1/4.', 'Area of the triangle-forming region is 1/8 of the square, but only half the square is valid (x < y).'], ['1/8', 'That is for a specific break order.', '1/4 is the standard result for simultaneous breaks.']] },
      { id: 19130, chapter: 'Probability', title: 'Poisson Process', prompt: 'In a Poisson process with rate lambda, what is the distribution of the time between successive events?', correct: 'Exponential with mean 1/lambda', wrong: [['Poisson', 'Poisson describes the COUNT of events, not the time between them.', 'Inter-arrival times are continuous.'], ['Normal', 'Times are strictly positive and skewed.', 'The exponential distribution is the only memoryless continuous one.'], ['Uniform', 'Events can happen very close together or very far apart.', 'PDF is lambda * e^(-lambda*t).']] },

      // Batch 2: Calculus & Linear Algebra
      { id: 19206, chapter: 'Linear Algebra', title: 'QR Decomposition', prompt: 'What does the QR decomposition of a matrix A represent?', correct: 'A = QR, where Q is orthogonal and R is upper triangular.', wrong: [['A = LU', 'That is Lower-Upper decomposition.', 'Q is the orthonormal basis.'], ['A = VDV^-1', 'That is Eigen-decomposition.', 'QR is used in the QR algorithm for eigenvalues.'], ['A = U Sigma V^T', 'That is Singular Value Decomposition.', 'QR uses Gram-Schmidt process.']] },
      { id: 19207, chapter: 'Calculus', title: 'Newton\'s Method', prompt: 'What is the iteration formula for Newton\'s method to find a root of f(x) = 0?', correct: 'x_{n+1} = x_n - f(x_n) / f\'(x_n)', wrong: [['x_{n+1} = x_n + f(x_n)', 'You need to account for the slope.', 'It uses the tangent line approximation.'], ['x_{n+1} = f(x_n) / x_n', 'That is not a root-finding formula.', 'The derivative is in the denominator.'], ['x_{n+1} = x_n - f\'(x_n) / f(x_n)', 'You inverted the ratio.', 'Slope = Rise / Run.']] },
      { id: 19208, chapter: 'Calculus', title: 'Lagrange Multipliers', prompt: 'When are Lagrange multipliers used?', correct: 'To find the local extrema of a function subject to equality constraints.', wrong: [['To solve differential equations', 'That is for other methods like variation of parameters.', 'It handles "maximize f(x) subject to g(x)=0".'], ['To calculate volumes', 'That is integration.', 'It uses the gradient of the objective and constraint.'], ['To find the roots of a polynomial', 'That is Newton\'s method or factoring.', 'Grad f = lambda * Grad g.']] },
      { id: 19209, chapter: 'Linear Algebra', title: 'LU Decomposition', prompt: 'What is the main advantage of LU decomposition for solving Ax = b?', correct: 'It allows for efficient solving for multiple different b vectors once A is factored.', wrong: [['It works for all matrices', 'It only works if the matrix can be reduced without row swaps (or with pivoting).', 'A = LU.'], ['It finds the eigenvalues', 'That is the QR algorithm.', 'It is essentially Gaussian elimination in matrix form.'], ['It reduces the rank of the matrix', 'Decompositions preserve rank.', 'L is lower triangular, U is upper triangular.']] },
      { id: 19210, chapter: 'Calculus', title: 'Jacobian Matrix', prompt: 'What is the Jacobian matrix of a vector-valued function?', correct: 'The matrix of all first-order partial derivatives.', wrong: [['The matrix of second derivatives', 'That is the Hessian matrix.', 'Jacobian is for F: R^n -> R^m.'], ['The inverse of the matrix', 'It is a derivative matrix.', 'It represents the best linear approximation.'], ['The determinant of the gradient', 'The Jacobian is the matrix itself; the Jacobian determinant is its determinant.', 'df_i / dx_j.']] },
      { id: 19211, chapter: 'Calculus', title: 'Integration by Parts', prompt: 'What is the result of the integral of x * e^x dx?', correct: '(x - 1) * e^x + C', wrong: [['x * e^x + C', 'You forgot to subtract the integral of v du.', 'Use u = x, dv = e^x dx.'], ['x^2 * e^x / 2', 'That is not how integration by parts works.', 'Integral u dv = uv - Integral v du.'], ['e^x + C', 'That is only the integral of e^x.', 'x * e^x - Integral e^x dx.']] },
      { id: 19212, chapter: 'Linear Algebra', title: 'Eigenvalues of A^n', prompt: 'If lambda is an eigenvalue of A, what is an eigenvalue of A^n?', correct: 'lambda^n', wrong: [['n * lambda', 'Eigenvalues scale exponentially with power.', 'If Av = lambda v, then A^2v = A(lambda v) = lambda^2 v.'], ['lambda / n', 'Powers increase the magnitude of eigenvalues > 1.', 'A^n preserves eigenvectors.'], ['1 / lambda^n', 'That would be for A^-n.', 'Apply the definition of eigenvalue repeatedly.']] },
      { id: 19213, chapter: 'Linear Algebra', title: 'Rank of Product', prompt: 'What is the upper bound for the rank of the product AB?', correct: 'min(rank(A), rank(B))', wrong: [['rank(A) + rank(B)', 'Rank cannot increase through multiplication.', 'The image of AB is a subspace of the image of A.'], ['rank(A) * rank(B)', 'That would far exceed the dimensions.', 'Multiplication can only "lose" information/dimensions.'], ['max(rank(A), rank(B))', 'The product is limited by its "weakest" (lowest rank) link.', 'Rank(AB) <= rank(A) and Rank(AB) <= rank(B).']] },
      { id: 19214, chapter: 'Linear Algebra', title: 'SVD', prompt: 'What is the Singular Value Decomposition (SVD)?', correct: 'A = U Sigma V^T, where U, V are orthogonal and Sigma is diagonal.', wrong: [['A = PDP^-1', 'That is eigendecomposition, which requires a square matrix.', 'SVD works for any m x n matrix.'], ['A = QR', 'That is for orthogonalization.', 'Sigma contains the singular values.'], ['A = LL^T', 'That is Cholesky decomposition for positive-definite matrices.', 'U and V are the left and right singular vectors.']] },
      { id: 19215, chapter: 'Calculus', title: 'Gradient Descent', prompt: 'In which direction does the gradient descent algorithm move?', correct: 'The direction of the negative gradient.', wrong: [['The direction of the positive gradient', 'That would be gradient ascent (maximizing).', 'The gradient points to the steepest increase.'], ['Towards the origin', 'It moves towards a local minimum of the function.', 'x = x - alpha * grad f.'], ['Perpendicular to the gradient', 'That would be moving along an isolevel curve.', 'Negative gradient is the steepest descent.']] },

      // Batch 2: Finance & Stochastic
      { id: 19311, chapter: 'Finance', title: 'Bull Spread', prompt: 'What is a bull call spread?', correct: 'Long a call with strike K1 and short a call with strike K2 (K1 < K2).', wrong: [['Long a call and long a put', 'That is a straddle.', 'A bull spread profits when the stock rises.'], ['Short a call and short a put', 'That is a short strangle.', 'It limits both risk and reward.'], ['Long a put with strike K1 and short a put with strike K2', 'That is a bull put spread (credit spread).', 'This specific question asks for a bull CALL spread.']] },
      { id: 19312, chapter: 'Finance', title: 'Binary Options', prompt: 'What is the payoff of a binary (digital) call option?', correct: 'A fixed amount (e.g., $1) if the stock is above the strike at maturity, else zero.', wrong: [['Max(S - K, 0)', 'That is a vanilla call option.', 'Binary options have a discontinuous payoff.'], ['Max(K - S, 0)', 'That is a vanilla put option.', 'The payoff is "all or nothing".'], ['The stock price itself', 'That is a forward contract or stock.', 'It is a bet on the price being above a threshold.']] },
      { id: 19313, chapter: 'Finance', title: 'Exchange Options', prompt: 'What is an exchange option?', correct: 'An option to exchange one asset for another (e.g., Asset A for Asset B).', wrong: [['An option traded on an exchange', 'While many are, the term "exchange option" refers to the payoff.', 'The payoff is Max(S1 - S2, 0).'], ['An option to buy a stock at the closing price', 'That is an ATM-at-close option.', 'Margrabe\'s formula is used to price them.'], ['An option to switch strikes', 'That is a chooser option.', 'It is a spread between two assets.']] },
      { id: 19314, chapter: 'Finance', title: 'Black-Scholes d1 and d2', prompt: 'In the Black-Scholes formula, what does N(d2) represent?', correct: 'The risk-neutral probability that the option expires in the money.', wrong: [['The delta of the option', 'That is N(d1).', 'd2 = d1 - sigma * sqrt(T).'], ['The expected stock price', 'That is related to S * e^(rt).', 'It is the strike-related probability.'], ['The time decay', 'That is Theta.', 'N(d2) is the probability of exercise in the risk-neutral measure.']] },
      { id: 19411, chapter: 'Finance', title: 'Portfolio Optimization', prompt: 'What is the goal of Markowitz mean-variance optimization?', correct: 'To find the portfolio with the minimum variance for a given expected return.', wrong: [['To maximize the number of assets', 'Diversification is a tool, not the objective.', 'It defines the efficient frontier.'], ['To pick the single best performing stock', 'It focuses on the entire portfolio and correlations.', 'Risk and return are balanced.'], ['To eliminate all risk', 'Risk cannot be eliminated, only optimized.', 'Covariance matrix is key.']] },
      { id: 19412, chapter: 'Finance', title: 'Sharpe Ratio', prompt: 'What is the formula for the Sharpe Ratio?', correct: '(Portfolio Return - Risk-Free Rate) / Portfolio Standard Deviation', wrong: [['Portfolio Return / Portfolio Variance', 'It uses standard deviation and subtracts the risk-free rate.', 'It measures excess return per unit of risk.'], ['Portfolio Beta / Portfolio Return', 'That is closer to the Treynor ratio.', 'Standard deviation is the denominator.'], ['Risk-Free Rate / Portfolio Return', 'The ratio measures the "reward" over the risk.', 'Higher is better.']] },
      { id: 19413, chapter: 'Finance', title: 'CAPM', prompt: 'According to the Capital Asset Pricing Model (CAPM), the expected return of an asset is:', correct: 'Risk-free rate + Beta * (Market Return - Risk-Free Rate)', wrong: [['Market Return + Beta', 'It is a weighted addition to the risk-free rate.', 'Only systematic risk is rewarded.'], ['Beta * Market Return', 'The risk-free rate is the baseline.', 'The term (Market - Risk-Free) is the market risk premium.'], ['Expected Dividend / Stock Price', 'That is the dividend yield.', 'Alpha is the excess return above CAPM.']] },
      { id: 19414, chapter: 'Finance', title: 'Beta', prompt: 'What does an asset\'s Beta (beta) represent in finance?', correct: 'The sensitivity of the asset\'s returns to the market returns.', wrong: [['The total risk of the asset', 'That is the standard deviation (sigma).', 'Beta measures systematic risk.'], ['The company\'s debt-to-equity ratio', 'That is leverage, which affects beta, but is not beta itself.', 'Market Beta is 1.0 by definition.'], ['The historical growth rate', 'It is a measure of correlation and relative volatility.', 'Cov(Ri, Rm) / Var(Rm).']] },
      { id: 19415, chapter: 'Finance', title: 'Duration and Convexity', prompt: 'How does a bond\'s price change relative to interest rates?', correct: 'Price moves inversely to rates; Duration handles linear change, Convexity handles the curvature.', wrong: [['Price moves in the same direction as rates', 'Higher rates mean lower present value of fixed coupons.', 'The relationship is non-linear.'], ['Price changes are always linear', 'Duration is only a first-order approximation.', 'Convexity is a second-order effect.'], ['Only Duration matters', 'For large rate changes, Convexity becomes significant.', 'Bond prices are "convex" to yields.']] },
      { id: 19416, chapter: 'Finance', title: 'Value at Risk (VaR)', prompt: 'What does a 1-day 95% Value at Risk (VaR) of $1M mean?', correct: 'There is a 5% chance the portfolio will lose more than $1M in a single day.', wrong: [['The portfolio will definitely lose $1M', 'It is a statistical threshold, not a certainty.', 'It describes the "left tail" of the distribution.'], ['The average loss is $1M', 'That would be Expected Shortfall (CVaR).', 'VaR is a quantile.'], ['The portfolio is safe for 95 days', 'It applies to any single day.', 'Losses can exceed VaR.']] },

      // Batch 3: Algorithms & Programming
      { id: 19501, chapter: 'Algorithms', title: 'Quicksort Complexity', prompt: 'What is the average-case and worst-case time complexity of Quicksort?', correct: 'Average: O(n log n), Worst: O(n^2)', wrong: [['O(n) for both', 'Sorting requires at least O(n log n) comparisons.', 'Worst case happens with poor pivot choices.'], ['O(n log n) for both', 'Merge sort is O(n log n) in worst case, but Quick sort is not.', 'Pivot selection is key.'], ['O(n^2) for both', 'Randomized pivot selection makes average case O(n log n).', 'Most implementations are efficient.']] },
      { id: 19502, chapter: 'Algorithms', title: 'Knuth Shuffle', prompt: 'How do you generate a random permutation of n elements in O(n) time?', correct: 'Iterate from i=0 to n-1, swapping element i with a random element from index i to n-1.', wrong: [['Sort with random keys', 'That is O(n log n).', 'Known as Fisher-Yates or Knuth shuffle.'], ['Swap every element with its neighbor', 'This does not produce all permutations with equal probability.', 'You need to pick from the remaining pool.'], ['Pick n random elements', 'That doesn\'t guarantee a permutation (could have duplicates).', 'Shuffle in-place.']] },
      { id: 19503, chapter: 'Algorithms', title: 'Reservoir Sampling', prompt: 'How do you pick a random element from a stream of unknown length such that every element has probability 1/n?', correct: 'Keep the k-th element with probability 1/k.', wrong: [['Store all elements in a list', 'The stream could be too large for memory.', 'Use a running probability.'], ['Pick the last element', 'That is only 1/n if you know n.', '1st element: 1/1. 2nd: 1/2. etc.'], ['Pick a random number up front', 'You don\'t know the range of the random number.', 'Prob(k is picked) = (1/k) * (k/k+1) * ... = 1/n.']] },
      { id: 19504, chapter: 'Algorithms', title: 'Find Max and Min', prompt: 'What is the minimum number of comparisons to find both the max and min of an array of n elements?', correct: '3n/2', wrong: [['n-1', 'That is only for one or the other.', 'Compare in pairs.'], ['2n-2', 'You can do better by comparing pairs first.', 'n/2 comparisons for pairs, then n/2 for min and n/2 for max.'], ['n log n', 'Comparison-based max/min is linear.', '3n/2 is the tight bound.']] },
      { id: 19505, chapter: 'Algorithms', title: 'Infinite Array Search', prompt: 'How do you find an element in an array of unknown (infinite) size?', correct: 'Check indices 1, 2, 4, 8... until you exceed the value, then binary search.', wrong: [['Linear search', 'Too slow for large indices.', 'O(n) vs O(log n).'], ['Start at a very large index', 'You might go way past it or hit an error.', 'Exponentially increase the range.'], ['It is impossible', 'Binary search can be adapted if you find a bound.', 'O(log n) complexity.']] },
      { id: 19506, chapter: 'Algorithms', title: '2D Matrix Search', prompt: 'How do you find a value in an n x n matrix where rows and columns are sorted?', correct: 'Start at top-right, move left if value is smaller, down if larger. O(n).', wrong: [['Binary search every row', 'That is O(n log n).', 'Use the 2D sorted property.'], ['Flatten and binary search', 'The matrix is not fully sorted in 1D order.', 'O(n^2) is too slow.'], ['Start at center', 'It is harder to prune the search space.', 'O(n) is the optimal linear scan.']] },
      { id: 19507, chapter: 'Algorithms', title: 'Fibonacci Efficiency', prompt: 'Why is the recursive F(n) = F(n-1) + F(n-2) slow?', correct: 'It computes the same subproblems many times, leading to O(2^n) complexity.', wrong: [['Memory overhead', 'The stack depth is only O(n).', 'The issue is redundant calculation.'], ['The addition is slow', 'Addition is constant time.', 'Use Dynamic Programming or Memoization.'], ['It uses too many variables', 'It uses the same variables, just too many calls.', 'Complexity is exponential.']] },
      { id: 19508, chapter: 'Algorithms', title: 'Linked List Cycle', prompt: 'How do you detect a cycle in a linked list with O(1) space?', correct: 'Use two pointers, one moving twice as fast as the other.', wrong: [['Use a Hash Set', 'That requires O(n) space.', 'Floyd\'s Cycle-Finding Algorithm.'], ['Reverse the list', 'This modifies the data structure.', 'Check if slow == fast.'], ['Count the nodes', 'You will loop forever if there is a cycle.', 'Fast and slow pointers.']] },
      { id: 19509, chapter: 'Algorithms', title: 'Stack using Queues', prompt: 'How can you implement a Stack using two Queues?', correct: 'On push, add to the empty queue and move all elements from the other queue to it.', wrong: [['It is impossible', 'Queues are FIFO, Stacks are LIFO, but it can be done.', 'One operation will be O(n).'], ['Just use one queue', 'You need two to reverse the order easily.', 'Push or Pop will be expensive.'], ['Reverse the queue every time', 'A queue cannot be reversed in O(1).', 'Use the second queue as a staging area.']] },
      { id: 19510, chapter: 'Algorithms', title: 'Count Set Bits', prompt: 'How do you count the number of 1s in a binary integer efficiently?', correct: 'Use n = n & (n - 1) repeatedly until n is 0.', wrong: [['Loop through all 32 bits', 'That is always 32 iterations.', 'Brian Kernighan\'s algorithm only iterates over set bits.'], ['Convert to string', 'Very inefficient.', 'Use bitwise AND.'], ['Divide by 2', 'That is essentially bit shifting.', 'n & (n-1) clears the least significant bit.']] },
      { id: 19511, chapter: 'Algorithms', title: 'Power of 2', prompt: 'How do you check if n is a power of 2 using bitwise operators?', correct: '(n > 0) && (n & (n - 1) == 0)', wrong: [['n % 2 == 0', 'That only checks if n is even.', 'Power of 2 has only one bit set.'], ['n >> 1', 'That divides by 2 but doesn\'t check the property.', 'Binary of 8 is 1000, 7 is 0111.'], ['log2(n) is integer', 'Log is expensive.', 'Bitwise is O(1).']] },
      { id: 19512, chapter: 'Algorithms', title: 'log(n!) Complexity', prompt: 'What is the Big O complexity of log(n!)?', correct: 'O(n log n)', wrong: [['O(n!)', 'Log reduces the factorial to a sum.', 'Use Stirling\'s approximation.'], ['O(n^2)', 'It is tighter than n^2.', 'n! is approximately (n/e)^n.'], ['O(log n)', 'Factorial grows much faster than that.', 'log(n!) = log(n) + log(n-1) + ...']] },

      // Batch 3: Advanced Probability
      { id: 19131, chapter: 'Probability', title: 'Secretary Problem', prompt: 'You interview n candidates one by one. You must decide immediately after each. What is the optimal strategy to pick the best one?', correct: 'Reject the first n/e candidates, then pick the first one better than all previous.', wrong: [['Pick the first candidate', 'Only 1/n chance of success.', 'You need to establish a baseline.'], ['Pick a random candidate', 'Does not maximize the probability of picking the BEST.', 'The optimal probability is 1/e.'], ['Reject the first half', 'n/2 is close but not optimal.', 'The optimal cutoff is n/e.']] },
      { id: 19132, chapter: 'Probability', title: 'Sum of Uniforms', prompt: 'What is the expected number of Uniform(0,1) variables to sum to more than 1?', correct: 'e', wrong: [['2', 'The average of one is 0.5, but the distribution is skewed.', 'P(N > n) = 1/n!'], ['3', 'Average is 2.718...', 'Sum 1/n! = e.'], ['1.5', 'At least 2 are usually needed.', 'Expected value is e.']] },
      { id: 19133, chapter: 'Probability', title: 'First Passage Time', prompt: 'In a standard Brownian Motion, what is the distribution of the first time it hits a level a > 0?', correct: 'Inverse Gaussian (Levy) distribution', wrong: [['Normal', 'Time is always positive.', 'The tail is heavy.'], ['Exponential', 'Passage time has a different scaling.', 'It is related to the reflection principle.'], ['Uniform', 'It can take arbitrarily long.', 'Expected hitting time is infinite.']] },
      { id: 19134, chapter: 'Probability', title: 'Reflection Principle', prompt: 'The probability that a Brownian Motion reaches level a by time T is equal to:', correct: '2 * P(W_T > a)', wrong: [['P(W_T > a)', 'You must account for paths that hit a and then drop back down.', 'By symmetry, half of paths hitting a end up below it.'], ['P(W_T < a)', 'That is the opposite.', 'Total probability of hitting a.'], ['0.5', 'Depends on a and T.', 'Known as the Bachelier formula.']] },
      { id: 19135, chapter: 'Probability', title: 'Unfair Gambler\'s Ruin', prompt: 'In Gambler\'s Ruin with p != 0.5, the probability of reaching N before 0 starting at i is:', correct: '((q/p)^i - 1) / ((q/p)^N - 1)', wrong: [['i / N', 'That is only for the symmetric (p=0.5) case.', 'q = 1-p.'], ['p^i', 'Does not account for the boundary at 0.', 'Use the characteristic equation.'], ['(p/q)^i', 'The terms are inverted.', 'Look at the ratio of q/p.']] },
      { id: 19136, chapter: 'Probability', title: 'Steady State', prompt: 'When does a discrete Markov chain have a unique steady state?', correct: 'If it is irreducible and aperiodic.', wrong: [['Always', 'Transient or periodic chains may not.', 'Irreducible means all states are reachable.'], ['If it has a sink node', 'A sink node makes the state absorbing, not a steady distribution.', 'Aperiodic avoids cycles.'], ['If the transition matrix is symmetric', 'Symmetry implies the steady state is uniform, but doesn\'t guarantee existence.', 'The chain must be "ergodic".']] },
      { id: 19137, chapter: 'Probability', title: 'Random Walk on Graph', prompt: 'In a random walk on a graph, the steady state probability of a node is proportional to:', correct: 'Its degree (number of edges)', wrong: [['Its distance from the center', 'Degree is the local connectivity.', 'Sum of degrees = 2 * edges.'], ['Constant (1/n)', 'Only for regular graphs where all degrees are equal.', 'Pi_i * P_ij = Pi_j * P_ji.'], ['The number of triangles it belongs to', 'Triangles affect local clustering, not just steady state.', 'Degree centrality.']] },

      // Batch 3: Linear Algebra & Calculus
      { id: 19216, chapter: 'Linear Algebra', title: 'Cholesky Decomposition', prompt: 'What type of matrix is required for Cholesky decomposition A = LL^T?', correct: 'Symmetric and Positive Definite', wrong: [['Any square matrix', 'Needs symmetry and positive eigenvalues.', 'Used for sampling from Multivariate Normal.'], ['Orthogonal', 'That is for QR or SVD.', 'L is lower triangular.'], ['Diagonal', 'Diagonal is already decomposed.', 'Generalizes sqrt to matrices.']] },
      { id: 19217, chapter: 'Linear Algebra', title: 'Positive Definite Check', prompt: 'How can you verify a matrix is Positive Definite?', correct: 'All eigenvalues are positive OR all upper-left subdeterminants are positive.', wrong: [['Determinant is positive', 'That is necessary but not sufficient.', 'All eigenvalues must be > 0.'], ['All elements are positive', 'A matrix with positive elements can be indefinite.', 'x^T A x > 0 for all x.'], ['It is invertible', 'Invertible only means non-zero eigenvalues.', 'Could be negative.']] },
      { id: 19218, chapter: 'Linear Algebra', title: 'Idempotent Matrix', prompt: 'What are the possible eigenvalues of an idempotent matrix (A^2 = A)?', correct: '0 or 1', wrong: [['Any real number', 'A(Av) = Av => lambda^2 v = lambda v.', 'lambda^2 - lambda = 0.'], ['-1 or 1', 'That is for an involuntary matrix (A^2 = I).', 'Projection matrices are idempotent.'], ['1 only', 'The zero matrix is idempotent and has eigenvalue 0.', 'Rank(A) = Trace(A).']] },
      { id: 19219, chapter: 'Linear Algebra', title: 'Trace Property', prompt: 'Which of the following is true for the trace of matrices?', correct: 'Trace(AB) = Trace(BA)', wrong: [['Trace(AB) = Trace(A) * Trace(B)', 'Trace is linear, not multiplicative.', 'Cyclic property.'], ['Trace(A) = Det(A)', 'Trace is sum of eigenvalues, Det is product.', 'Only true for 1x1.'], ['Trace(A^T) = -Trace(A)', 'Trace is invariant under transposition.', 'Trace(A^T) = Trace(A).']] },
      { id: 19220, chapter: 'Linear Algebra', title: 'Orthogonal Determinant', prompt: 'What is the determinant of an orthogonal matrix (Q^T Q = I)?', correct: '+1 or -1', wrong: [['1 only', 'Could be a reflection (det = -1).', 'Det(Q)^2 = Det(I) = 1.'], ['0', 'Orthogonal matrices are always invertible.', 'Rank is full.'], ['Any value on the unit circle', 'For real matrices, it must be real (+/- 1).', 'Complex orthogonal matrices (unitary) have det with magnitude 1.']] },
      { id: 19221, chapter: 'Calculus', title: 'Hessian Matrix', prompt: 'What does the Hessian matrix represent?', correct: 'The matrix of second-order partial derivatives.', wrong: [['The gradient vector', 'Gradient is first-order.', 'Used to check for local minima/maxima.'], ['The Jacobian', 'Jacobian is for vector functions; Hessian is for scalar.', 'Df^2.'], ['The matrix of eigenvalues', 'No, but its eigenvalues tell you about curvature.', 'Positive definite Hessian implies convexity.']] },
      { id: 19222, chapter: 'Calculus', title: 'Log Taylor Series', prompt: 'What is the Taylor series for ln(1+x) around x=0?', correct: 'x - x^2/2 + x^3/3 - x^4/4 ...', wrong: [['1 + x + x^2 + ...', 'That is 1/(1-x).', 'No factorial in the denominator for log.'], ['x + x^2/2! + x^3/3! + ...', 'That is e^x - 1.', 'Alternating signs for ln(1+x).'], ['x - x^3/3! + x^5/5! ...', 'That is sin(x).', 'Derivative of ln(1+x) is 1/(1+x).']] },
      { id: 19223, chapter: 'Calculus', title: 'Quadratic Gradient', prompt: 'What is the gradient of f(x) = x^T A x with respect to x (for symmetric A)?', correct: '2Ax', wrong: [['Ax', 'The power rule applies to quadratic forms.', 'd(x^T A x) = 2x^T A.'], ['A', 'The result must be a vector.', 'Like the derivative of ax^2 being 2ax.'], ['x^T A', 'That is the transpose of the gradient.', 'Standard form is 2Ax.']] },

      // Batch 3: More Finance & Greeks
      { id: 19315, chapter: 'Finance', title: 'Vega', prompt: 'What does the Greek "Vega" measure?', correct: 'Sensitivity of option price to changes in implied volatility.', wrong: [['Sensitivity to stock price', 'That is Delta.', 'Vega is always positive for vanilla options.'], ['Sensitivity to time', 'That is Theta.', 'Higher volatility increases option value.'], ['Sensitivity to interest rates', 'That is Rho.', 'dv / dsigma.']] },
      { id: 19316, chapter: 'Finance', title: 'Rho', prompt: 'What does the Greek "Rho" measure?', correct: 'Sensitivity of option price to changes in interest rates.', wrong: [['Sensitivity to dividends', 'That is Phi.', 'Calls have positive Rho, Puts have negative Rho.'], ['Sensitivity to volatility', 'That is Vega.', 'dr / dr.'], ['Sensitivity to maturity', 'That is not a standard Greek name.', 'Interest rates affect the cost of carry.']] },
      { id: 19317, chapter: 'Finance', title: 'Straddle Gamma', prompt: 'What is the Gamma of a long straddle (Long Call + Long Put same strike)?', correct: 'Twice the Gamma of a single option (very high).', wrong: [['Zero', 'Gamma is the second derivative; for both call and put it is positive.', 'Both benefit from large moves.'], ['Negative', 'Short positions have negative gamma.', 'Long positions are always long gamma.'], ['It depends on the delta', 'Gamma is independent of delta but related to vol/time.', 'Straddle is a pure volatility play.']] },
      { id: 19318, chapter: 'Finance', title: 'Theta-Gamma Trade-off', prompt: 'In the Black-Scholes PDE, what is the relationship between Theta and Gamma?', correct: 'Theta + 0.5 * sigma^2 * S^2 * Gamma + rS * Delta = rV', wrong: [['Theta = Gamma', 'They have opposite signs for long positions.', 'Time decay offsets the benefit of convexity.'], ['Theta * Gamma = 1', 'No, they are additive in the PDE.', 'Gamma is the profit from moves, Theta is the cost of waiting.'], ['They are unrelated', 'The BS PDE links all Greeks together.', 'Delta-hedged portfolios earn the risk-free rate.']] },
      { id: 19319, chapter: 'Finance', title: 'Implied Volatility Smile', prompt: 'What is the "Volatility Smile"?', correct: 'The pattern where OTM puts and calls have higher implied volatility than ATM options.', wrong: [['The historical volatility trend', 'IV is forward-looking.', 'Common in equity markets (Skew) and FX (Smile).'], ['A sign of a bullish market', 'It is a property of option pricing, not market direction.', 'Reflects non-normal tails.'], ['The relationship between Delta and Gamma', 'No, it is IV vs Strike.', 'Markets price in "fat tails".']] },
      { id: 19320, chapter: 'Finance', title: 'Asian Options', prompt: 'What is an Asian Option?', correct: 'An option whose payoff depends on the average price of the underlying asset.', wrong: [['An option traded in Asia', 'The name refers to the payoff structure.', 'Averaging reduces volatility.'], ['An option on a basket of Asian stocks', 'No, it refers to the path-dependency.', 'Cheaper than vanilla options.'], ['An option that expires at noon', 'That is a time-of-day option.', 'Payoff = Max(Average - K, 0).']] },
      { id: 19321, chapter: 'Finance', title: 'Barrier Options', prompt: 'What is a "Knock-out" option?', correct: 'An option that becomes worthless if the underlying hits a certain price level.', wrong: [['An option that pays out if a barrier is hit', 'That is a "Knock-in" option.', 'Path-dependent.'], ['An option on a bankruptcy', 'No, it refers to a price barrier.', 'Down-and-out, Up-and-out, etc.'], ['An option with no strike', 'It has a strike and a barrier.', 'Cheaper than vanilla options.']] },
      { id: 19322, chapter: 'Finance', title: 'Lookback Options', prompt: 'What is a Lookback Option?', correct: 'An option whose payoff depends on the maximum or minimum price reached.', wrong: [['An option that lets you change your mind', 'No, it uses the historical extreme.', 'Payoff = S_T - Min(S).'], ['An option on historical data', 'It is a forward-looking contract.', 'Extremely expensive.'], ['A binary option on the high price', 'It is usually a floating or fixed strike on the extreme.', 'Max convexity.']] },
      { id: 19323, chapter: 'Finance', title: 'Risk-Neutral Martingale', prompt: 'In the risk-neutral measure, which process is a martingale?', correct: 'The discounted stock price (S_t / B_t)', wrong: [['The stock price (S_t)', 'Stock grows at the risk-free rate on average.', 'E[S_T] = S_0 * e^(rT).'], ['The option price (V_t)', 'Option price also grows at r.', 'Only the discounted version is a martingale.'], ['Volatility (sigma)', 'Volatility is usually assumed constant or mean-reverting.', 'Martingale property is key for pricing.']] },
      { id: 19324, chapter: 'Finance', title: 'Put Delta', prompt: 'What is the Delta of a European Put option in Black-Scholes?', correct: 'N(d1) - 1 (or -N(-d1))', wrong: [['N(d1)', 'That is the Delta of a Call.', 'Put delta is between -1 and 0.'], ['-N(d2)', 'No, it uses d1 for the hedge ratio.', 'Put-Call Parity: Delta_C - Delta_P = 1.'], ['N(d2) - 1', 'No, N(d1) is the standard term.', 'Delta is the sensitivity to the underlying.']] },

      // Batch 3.5: Statistics & More
      { id: 19146, chapter: 'Probability', title: 'MLE', prompt: 'What is the principle of Maximum Likelihood Estimation (MLE)?', correct: 'To find the parameter values that maximize the probability of the observed data.', wrong: [['To minimize the error', 'That is closer to Least Squares.', 'MLE is a general statistical framework.'], ['To find the mean of the data', 'The mean is often the MLE for some distributions, but not all.', 'Maximize L(theta).'], ['To ensure the model is unbiased', 'MLEs can be biased (e.g., sample variance).', 'Focus on the likelihood function.']] },
      { id: 19147, chapter: 'Probability', title: 'Sample Variance Bias', prompt: 'Why do we divide by n-1 instead of n when calculating sample variance?', correct: 'To make the estimator unbiased; dividing by n underestimates the population variance.', wrong: [['Because n-1 is easier to calculate', 'No, it is a mathematical correction.', 'Bessel\'s correction.'], ['To account for outliers', 'It accounts for the fact that the sample mean is also estimated.', 'Degrees of freedom.'], ['Because the last data point is fixed', 'One degree of freedom is lost to the mean.', 'E[s^2] = sigma^2 only with n-1.']] },
      { id: 19148, chapter: 'Probability', title: 'Law of Large Numbers', prompt: 'What is the difference between the Weak and Strong Law of Large Numbers?', correct: 'Weak Law implies convergence in probability; Strong Law implies almost sure convergence.', wrong: [['Weak Law is for small samples', 'Both are asymptotic (as n goes to infinity).', 'The mode of convergence differs.'], ['Strong Law only works for Normal distributions', 'Both apply to any distribution with finite mean.', 'Almost sure convergence is a stronger condition.'], ['There is no difference', 'Mathematically, they are distinct results.', 'Convergence in probability vs convergence with probability 1.']] },
      { id: 19513, chapter: 'Algorithms', title: 'Knapsack Problem', prompt: 'What is the time complexity of the 0/1 Knapsack problem using Dynamic Programming?', correct: 'O(n * W) where n is items and W is capacity.', wrong: [['O(2^n)', 'That is the brute force complexity.', 'DP makes it pseudo-polynomial.'], ['O(n log n)', 'That is for the fractional knapsack (greedy).', 'It depends on the capacity.'], ['O(n^2)', 'It depends on both n and W.', 'Space complexity is also O(W) or O(n*W).']] },
      { id: 19514, chapter: 'Algorithms', title: 'Longest Common Subsequence', prompt: 'What is the time complexity of finding the LCS of two strings of length n and m?', correct: 'O(n * m)', wrong: [['O(n + m)', 'You must compare all pairs of prefixes.', 'Standard DP approach.'], ['O(2^n)', 'Recursive without memoization is exponential.', 'O(nm) is the efficient version.'], ['O(n log n)', 'Not possible with standard character comparisons.', 'Space is also O(nm) or O(min(n,m)).']] },
      { id: 19515, chapter: 'Algorithms', title: 'Dijkstra\'s Algorithm', prompt: 'What is the time complexity of Dijkstra\'s algorithm using a binary heap?', correct: 'O((V + E) log V)', wrong: [['O(V^2)', 'That is for the simple array implementation.', 'Heap improves the edge relaxation step.'], ['O(E log E)', 'Close, but E can be V^2.', 'V is the number of vertices, E is edges.'], ['O(V + E)', 'Only if you use a Fibonacci heap (O(E + V log V)).', 'Binary heap is the standard implementation.']] },
      { id: 19224, chapter: 'Calculus', title: 'Divergence vs Curl', prompt: 'In vector calculus, what does the Divergence of a field represent?', correct: 'The net flow out of a point (scalar).', wrong: [['The rotation around a point', 'That is the Curl (vector).', 'Div F = grad . F.'], ['The magnitude of the field', 'No, it is a derivative.', 'Zero divergence means incompressible flow.'], ['The direction of steepest increase', 'That is the Gradient.', 'Dot product vs Cross product.']] },
      { id: 19225, chapter: 'Calculus', title: 'Fundamental Theorem', prompt: 'What does the Fundamental Theorem of Calculus link?', correct: 'Differentiation and Integration as inverse operations.', wrong: [['Addition and Multiplication', 'No, it is about rates and totals.', 'Integral of f\' is f(b) - f(a).'], ['Limits and Continuity', 'Those are foundations for the theorem.', 'Provides a way to compute integrals easily.'], ['Algebra and Geometry', 'In a way, yes, but specifically for derivatives/integrals.', 'Newton-Leibniz formula.']] },
      { id: 19325, chapter: 'Finance', title: 'CVA', prompt: 'What is Credit Valuation Adjustment (CVA)?', correct: 'An adjustment to the value of a derivative to account for counterparty default risk.', wrong: [['An adjustment for market volatility', 'That is a volatility adjustment.', 'CVA is a price for credit risk.'], ['The cost of capital', 'That is KVA.', 'It is the expected loss from default.'], ['The tax on derivatives', 'No, it is a risk management metric.', 'DVA is the mirror image.']] },
      { id: 19326, chapter: 'Finance', title: 'Correlation Swap', prompt: 'What is a Correlation Swap?', correct: 'A derivative where the payoff is based on the realized average correlation of a basket of assets.', wrong: [['A swap of two different currencies', 'That is a cross-currency swap.', 'Used to hedge dispersion.'], ['A swap of stock for bonds', 'That is an asset swap.', 'Pure play on co-movement.'], ['An agreement to fix the correlation', 'The payoff is floating realized vs fixed strike.', 'Common in equity index trading.']] },
      { id: 19327, chapter: 'Finance', title: 'Variance Swap', prompt: 'What is a Variance Swap?', correct: 'A derivative with a payoff proportional to the difference between realized variance and a fixed strike.', wrong: [['An option on volatility', 'It is a forward contract on variance, not an option.', 'Linear payoff in variance.'], ['A swap of dividends for price growth', 'No.', 'Pure volatility exposure.'], ['A way to hedge linear price risk', 'It hedges volatility risk, not price direction.', 'Symmetry in returns.']] },
      { id: 19328, chapter: 'Finance', title: 'Model Risk', prompt: 'What is "Model Risk" in quantitative finance?', correct: 'The risk that a financial model is incorrect or used inappropriately, leading to losses.', wrong: [['The risk of a computer crashing', 'That is operational risk.', 'Garbage in, garbage out.'], ['The risk of market prices changing', 'That is market risk.', 'Mispricing due to wrong assumptions.'], ['The risk of a trader cheating', 'That is fraud or operational risk.', 'Black-Scholes being used when its assumptions fail is model risk.']] },

      // Batch 4: Advanced Math & Finance (Joshi)
      { id: 19228, chapter: 'Calculus', title: 'Newton-Raphson', prompt: 'What is the Newton-Raphson update rule for finding a root of f(x) = 0?', correct: 'x_new = x - f(x) / f\'(x)', wrong: [['x_new = x - f\'(x) / f(x)', 'You divide by the derivative, not the function value.', 'Tangent line intersection.'], ['x_new = x + f(x) * f\'(x)', 'That is not the root-finding rule.', 'Linear approximation.'], ['x_new = x / f\'(x)', 'Forgets the starting point x.', 'Convergence is quadratic near the root.']] },
      { id: 19229, chapter: 'Linear Algebra', title: 'Cholesky Decomposition', prompt: 'What is the Cholesky decomposition of a matrix A?', correct: 'A = LL^T, where L is a lower triangular matrix with positive diagonal entries.', wrong: [['A = LU', 'That is standard Gaussian elimination.', 'Requires A to be symmetric positive definite.'], ['A = QR', 'QR uses an orthogonal matrix Q.', 'Used for sampling correlated normals.'], ['A = PDP^-1', 'That is eigen-decomposition.', 'L is the "square root" of the matrix.']] },
      { id: 19230, chapter: 'Linear Algebra', title: 'QR Decomposition', prompt: 'What is the QR decomposition used for in quant finance?', correct: 'Solving least squares problems and finding eigenvalues (QR algorithm).', wrong: [['Pricing options directly', 'It is a numerical building block, not a pricing model.', 'Orthogonalization.'], ['Simulating stock paths', 'Usually Cholesky or SVD is used for correlation.', 'Q is orthogonal, R is upper triangular.'], ['Calculating the Greeks', 'Finite differences are more common.', 'Stable matrix inversion.']] },
      { id: 19341, chapter: 'Finance', title: 'Digital Option Replication', prompt: 'How do you replicate a digital call (pays 1 if S > K) using vanilla calls?', correct: 'A tight bull spread: (Call(K-e) - Call(K+e)) / 2e.', wrong: [['A single call at K', 'A call has a linear payoff, not a step payoff.', 'The slope at K must be infinite.'], ['A put and a call', 'That is a straddle or forward.', 'Limit of a narrow spread.'], ['It cannot be replicated', 'It can be approximated with high accuracy using vanillas.', 'Infinite gamma at the strike.']] },
      { id: 19342, chapter: 'Finance', title: 'Put-Call Parity (Dividends)', prompt: 'What is the Put-Call Parity formula for a stock with a continuous dividend yield q?', correct: 'C - P = S*e^(-qT) - K*e^(-rT)', wrong: [['C - P = S - K', 'Ignores interest and dividends.', 'Cost of carry logic.'], ['C - P = S*e^(rT) - K', 'No, K is the future value.', 'Dividends reduce the value of the call relative to the put.'], ['C + P = S + K', 'No.', 'Static replication via forward.']] },
      { id: 19343, chapter: 'Finance', title: 'Butterfly Spread', prompt: 'What does a Butterfly Spread (Long K1, Short 2*K2, Long K3) bet on?', correct: 'Low volatility; the stock price staying near the middle strike K2.', wrong: [['High volatility', 'That would be a Straddle or Strangle.', 'Negative Gamma in the middle.'], ['Stock price going up', 'It is delta-neutral if centered.', 'Peak payoff at K2.'], ['Interest rate changes', 'Primarily a vol/price play.', 'Limited risk, limited reward.']] },
      { id: 19344, chapter: 'Finance', title: 'Delta of a Call', prompt: 'In Black-Scholes, what is the Delta of a European Call?', correct: 'N(d1)', wrong: [['N(d2)', 'N(d2) is the risk-neutral probability of being in-the-money.', 'Delta is the sensitivity to spot.'], ['e^-rT * N(d1)', 'No, the S term in the formula has no discount.', 'Always between 0 and 1.'], ['1 - N(d1)', 'That is the Delta of a Put (with a minus sign).', 'Increases as S increases.']] },
      { id: 19345, chapter: 'Finance', title: 'Gamma of an Option', prompt: 'What does Gamma represent?', correct: 'The rate of change of Delta with respect to the stock price.', wrong: [['Sensitivity to time', 'That is Theta.', 'Second derivative of price.'], ['Sensitivity to volatility', 'That is Vega.', 'Highest for ATM options.'], ['Sensitivity to rates', 'That is Rho.', 'Measures the curvature.']] },
      { id: 19346, chapter: 'Finance', title: 'Theta of a Call', prompt: 'Is the Theta of a European Call usually positive or negative?', correct: 'Negative (time decay)', wrong: [['Positive', 'Options usually lose value as time passes.', 'Theta is "rent" paid for the optionality.'], ['Zero', 'Time decay is a fundamental property.', 'Bleeds value every day.'], ['Only negative for ITM', 'Negative for all strikes (usually).', 'Ceteris paribus, shorter time = lower value.']] },
      { id: 19347, chapter: 'Finance', title: 'Vega and Maturity', prompt: 'How does Vega change as time to maturity increases?', correct: 'Vega increases with maturity (longer options are more sensitive to vol).', wrong: [['Vega decreases', 'No, longer time means more "room" for vol to act.', 'Sensitivity scales with sqrt(T).'], ['Vega stays constant', 'No.', 'Longer-dated options carry more vol risk.'], ['Vega is only for short-term options', 'No.', 'Vega = S * sqrt(T) * n(d1).']] },
      { id: 19348, chapter: 'Finance', title: 'Straddle', prompt: 'What is a Straddle?', correct: 'Buying both a call and a put with the same strike and maturity.', wrong: [['Buying two calls', 'That is just more delta.', 'Bet on high volatility.'], ['Selling a call and buying a put', 'That is a synthetic short.', 'Delta-neutral but long gamma/vega.'], ['Buying a call and selling a put', 'That is a synthetic long.', 'V-shaped payoff.']] },
      { id: 19524, chapter: 'Algorithms', title: 'Importance Sampling', prompt: 'When is Importance Sampling useful in Monte Carlo pricing?', correct: 'When pricing deep out-of-the-money options to reduce variance.', wrong: [['When the model is very simple', 'Standard MC works fine there.', 'Focuses samples on the "important" region.'], ['To speed up the random number generator', 'No, it changes the distribution, not the generator speed.', 'Change of measure.'], ['Only for American options', 'Useful for any rare-event simulation.', 'Likelihood ratio method.']] },
      { id: 19151, chapter: 'Probability', title: 'Central Limit Theorem', prompt: 'What does the Central Limit Theorem state about the sum of i.i.d. variables?', correct: 'The sum (or mean) tends toward a Normal distribution as N increases, regardless of the original distribution.', wrong: [['The sum tends toward zero', 'No.', 'Requires finite variance.'], ['The variables must be Normal', 'No, that is the beauty of CLT.', 'Distribution of the sample mean.'], ['The variance goes to zero', 'The variance of the *mean* goes to zero, but the distribution is Normal.', 'Foundation of statistics.']] },
      { id: 19152, chapter: 'Probability', title: 'Correlation vs Causation', prompt: 'Can a correlation of 0.9 between X and Y prove that X causes Y?', correct: 'No, there could be a latent "common cause" Z or it could be a coincidence.', wrong: [['Yes, if it is statistically significant', 'Significance doesn\'t imply direction.', 'Spurious correlation.'], ['Yes, if the sample size is large', 'Sample size doesn\'t help with causality.', 'Post hoc ergo propter hoc.'], ['Only if X comes before Y', 'Temporal precedence is necessary but not sufficient.', 'Causality requires a mechanism.']] },
      { id: 19153, chapter: 'Probability', title: 'Conditional Probability', prompt: 'If P(A) = 0.3 and P(B) = 0.4 and they are independent, what is P(A|B)?', correct: '0.3', wrong: [['0.12', 'That is P(A and B).', 'Independence means P(A|B) = P(A).'], ['0.7', 'That is P(A or B) - P(A and B).', 'B provides no info about A.'], ['0.4', 'No.', 'P(A|B) is the updated probability.']] },
      { id: 19349, chapter: 'Finance', title: 'Risk-Neutral Measure', prompt: 'In the risk-neutral measure, what is the expected return of any tradable asset?', correct: 'The risk-free rate r.', wrong: [['The market return', 'No, risk premia are removed.', 'Martingale pricing.'], ['Zero', 'Only if interest rates are zero.', 'Discounted price is a martingale.'], ['The asset\'s alpha', 'Alpha is zero in this measure.', 'Fundamental Theorem of Asset Pricing.']] },
      { id: 19516, chapter: 'Algorithms', title: 'Numerical Integration', prompt: 'What is Simpson\'s Rule for numerical integration?', correct: 'A method that uses parabolic segments to approximate the area under a curve, requiring an even number of intervals.', wrong: [['The Trapezoidal Rule', 'Trapezoids use linear segments; Simpson\'s uses quadratic.', 'Integral approx (h/3)*(f0 + 4f1 + f2 + ...)'], ['Monte Carlo Integration', 'Monte Carlo is stochastic; Simpson\'s is deterministic.', 'Higher order accuracy than trapezoids.'], ['Rectangular Rule', 'The simplest method, using constant values.', 'Simpson\'s uses 1-4-1 weighting.']] },
      { id: 19517, chapter: 'Algorithms', title: 'Discrete Sampling', prompt: 'How do you sample from a discrete distribution with probabilities p1...pn using a Uniform(0,1) variable U?', correct: 'Calculate cumulative probabilities Ck = sum(p1...pk) and find k such that Ck-1 < U <= Ck.', wrong: [['Multiply U by the largest p', 'That doesn\'t map correctly to the individual probabilities.', 'Use the Inverse Transform Sampling principle.'], ['Pick the index k = floor(U * n)', 'That only works for a uniform discrete distribution.', 'Binary search the cumulative array for speed.'], ['Take the average of U and p', 'No logical basis.', 'Partition the [0,1] interval.']] },
      { id: 19518, chapter: 'Algorithms', title: 'Date Increment', prompt: 'What is the "Leap Year" rule for the year 2000 vs 2100?', correct: '2000 was a leap year (divisible by 400), but 2100 will not be (divisible by 100 but not 400).', wrong: [['Both are leap years', 'Century years must be divisible by 400 to be leap years.', 'The 400-year cycle correction.'], ['Neither are leap years', '2000 followed the 400-year rule.', 'Every 4 years, except centuries, unless 400.'], ['2100 is a leap year', 'No, 2100 is not divisible by 400.', 'Gregorian calendar logic.']] },
      { id: 19519, chapter: 'Algorithms', title: 'Matrix Exponentiation', prompt: 'How can you efficiently compute M^n for a matrix M and large n?', correct: 'Binary exponentiation (Exponentiation by Squaring) in O(log n) matrix multiplications.', wrong: [['Multiply M by itself n times', 'That is O(n), too slow for very large n.', 'M^8 = ((M^2)^2)^2.'], ['Diagonalize and exponentiate', 'Only works if M is diagonalizable; computation of eigen-decomposition is expensive.', 'Square the matrix at each step.'], ['Add M to itself n times', 'That is n*M, not M^n.', 'Complexity is O(log n * matrix_mult_cost).']] },
      { id: 19520, chapter: 'Algorithms', title: 'sin(x)/x Stability', prompt: 'How should you implement f(x) = sin(x)/x to be stable at x = 0?', correct: 'Return 1 if |x| is very small, or use the Taylor expansion x - x^3/6 + ...', wrong: [['Use a try/catch for division by zero', 'The limit is 1, not an error.', 'Avoids NaN.'], ['Return 0', 'The limit of sin(x)/x as x goes to 0 is 1.', 'Small-angle approximation.'], ['Use a very small epsilon in the denominator', 'Causes precision loss.', 'Taylor series is the robust choice.']] },
      { id: 19521, chapter: 'Algorithms', title: 'Max Subarray Sum', prompt: 'What is Kadane\'s Algorithm used for?', correct: 'Finding the contiguous subarray with the largest sum in O(n) time.', wrong: [['Sorting an array', 'Kadane\'s is for the maximum sum problem.', 'Maintain a running local maximum.'], ['Finding the shortest path', 'That is Dijkstra or BFS.', 'Greedy + DP approach.'], ['Matrix multiplication', 'No.', 'Total complexity O(n).']] },
      { id: 19522, chapter: 'Algorithms', title: 'Submarine Interception', prompt: 'A submarine starts at an unknown integer p and moves v units/turn. Can you hit it with a missile?', correct: 'Yes, by enumerating all pairs (p, v) and checking one pair per turn.', wrong: [['No, there are too many possibilities', 'The set of pairs (p, v) is countable.', 'You will eventually hit it.'], ['Only if you know the starting position', 'You can guess p and v systematically.', 'Cantor\'s diagonal argument.'], ['Only if it moves slowly', 'Speed v can be any integer.', 'Infinite but countable search space.']] },
      { id: 19523, chapter: 'Algorithms', title: 'Robot Collision', prompt: 'Two robots on a line have identical code. How can they collide if they land at different spots?', correct: 'Move in one direction and check for the other\'s parachute; if found, change speed or behavior.', wrong: [['Move toward each other', 'They don\'t know where the other is.', 'The code must be identical.'], ['Wait at the starting spot', 'If both wait, they never meet.', 'Break the symmetry using the environment.'], ['Random walk', 'Not guaranteed to meet in finite time with identical logic.', 'Use the parachute as a marker.']] },
      { id: 19330, chapter: 'Finance', title: 'BS PDE Boundary', prompt: 'What is the boundary condition for a European Call at S=0?', correct: 'Value = 0', wrong: [['Value = Strike', 'If the stock is worthless and stays worthless, the call is worthless.', 'S=0 is an absorbing barrier.'], ['Value = Infinity', 'No, the stock price is the cap.', 'C(0, t) = 0.'], ['Value = -K', 'Option prices cannot be negative.', 'Lower bound is 0.']] },
      { id: 19331, chapter: 'Finance', title: 'Drift and Pricing', prompt: 'Two stocks have the same volatility but different drifts. How do their European call prices compare?', correct: 'They are identical because pricing is done in the risk-neutral measure.', wrong: [['The one with higher drift is more expensive', 'In risk-neutral world, both grow at r.', 'Investors are hedged.'], ['The one with lower drift is more expensive', 'No.', 'Only volatility and r matter.'], ['It depends on the strike', 'No, the drift is replaced by r for all strikes.', 'Girsanov Theorem.']] },
      { id: 19332, chapter: 'Finance', title: 'Time-Dependent Vol', prompt: 'How do you price an option if volatility is a deterministic function sigma(t)?', correct: 'Use the Black-Scholes formula with the root-mean-square average volatility over the period.', wrong: [['Use the volatility at expiry', 'You must account for the path.', 'Integral of sigma^2 over time.'], ['Use the initial volatility', 'Ignores future changes.', 'Average variance matters.'], ['It is impossible to price', 'It is solvable if sigma(t) is known.', 'Replace sigma^2*T with the integral.']] },
      { id: 19333, chapter: 'Finance', title: 'American Call Early Exercise', prompt: 'Is it ever optimal to early exercise an American Call on a non-dividend paying stock?', correct: 'No, it is always better to wait or sell the option.', wrong: [['Yes, if the stock is very high', 'The time value and interest on the strike make waiting better.', 'You lose the insurance value.'], ['Yes, if interest rates are high', 'Higher rates make the strike payment cheaper in the future.', 'Waiting is still optimal.'], ['Only at the 90th percentile', 'No, strictly suboptimal for non-dividend stocks.', 'Put early exercise can be optimal.']] },
      { id: 19334, chapter: 'Finance', title: 'American Put Early Exercise', prompt: 'Is it ever optimal to early exercise an American Put?', correct: 'Yes, if the stock price is low enough to offset the loss of time value.', wrong: [['No, never', 'Unlike calls, the maximum payoff is fixed at K.', 'Interest on the cash K becomes more valuable than the option.'], ['Only if the stock goes to zero', 'Exercise is optimal even before zero.', 'Depends on r and sigma.'], ['Only if volatility is zero', 'Low volatility makes it more likely, but not required.', 'Early exercise boundary.']] },
      { id: 19335, chapter: 'Finance', title: 'ATM Call Rule of Thumb', prompt: 'What is a good approximation for the value of an ATM 1-month call with S=100 and 20% vol?', correct: 'Approximately 0.4 * S * sigma * sqrt(T)', wrong: [['$1', 'Too low for 20% vol.', 'Roughly 2-3% of spot.'], ['$10', 'Too high for one month.', 'sqrt(1/12) is about 0.28.'], ['$5', 'A bit high.', '0.4 * 100 * 0.2 * 0.28 = 2.24.']] },
      { id: 19336, chapter: 'Finance', title: 'Volatility to Infinity', prompt: 'What happens to the price of a European Call as volatility tends to infinity?', correct: 'It tends to the current stock price S.', wrong: [['It tends to infinity', 'The call cannot be worth more than the stock itself.', 'Upper bound is S.'], ['It tends to the strike K', 'No, the chance of being deep ITM goes to 1.', 'S - Ke^-rT as vol -> inf.'], ['It goes to zero', 'Higher vol always increases vanilla option value.', 'Max payout is S.']] },
      { id: 19337, chapter: 'Finance', title: 'Mean Reversion', prompt: 'Does mean reversion in the stock price affect European option pricing in the Black-Scholes model?', correct: 'No, because the drift is replaced by the risk-free rate in the pricing measure.', wrong: [['Yes, it decreases the price', 'Only if it affects the local volatility.', 'Drift doesn\'t matter.'], ['Yes, it increases the price', 'No.', 'Risk-neutrality removes drift effects.'], ['Only for long-dated options', 'Still no, under standard BS assumptions.', 'Hedging neutralizes the drift.']] },
      { id: 19338, chapter: 'Finance', title: 'Call Convexity', prompt: 'The price of a call option is a _____ function of the strike price K.', correct: 'Convex', wrong: [['Concave', 'A butterfly spread (long 2 strikes, short middle) has positive value.', 'C\'\'(K) = e^-rT * pdf(K).'], ['Linear', 'The payoff is piecewise linear, but the price is curved.', 'Gamma is positive.'], ['Monotonically increasing', 'Call price decreases as strike increases.', 'C(K) is decreasing and convex.']] },
      { id: 19339, chapter: 'Finance', title: 'Static Hedge Error', prompt: 'What is the "Stop-Loss" hedging trap (buying at S=K, selling at S=K)?', correct: 'Transaction costs and "whipsawing" as the stock crosses the strike repeatedly.', wrong: [['It is a perfect hedge', 'In theory yes, in continuous time no.', 'Infinite trades required.'], ['It requires too much capital', 'It requires exactly K.', 'The error is the cost of crossing the spread.'], ['The stock might gap over K', 'Gapping is an issue, but even smooth paths are problematic due to gamma.', 'Accumulated hedging costs.']] },
      { id: 19340, chapter: 'Finance', title: 'Forward Price', prompt: 'What is the 1-year forward price of a $100 stock with 5% rates and a $2 dividend in 6 months?', correct: '100 * e^0.05 - 2 * e^(0.05 * 0.5)', wrong: [['$103', 'Must discount the dividend.', 'F = (S-D)e^rT.'], ['$105', 'Forgets the dividend entirely.', 'Dividends reduce the forward price.'], ['$98', 'Ignores the interest on the stock.', 'Cost of carry minus yield.']] },
      { id: 19226, chapter: 'Linear Algebra', title: 'Unitary Matrix', prompt: 'What is a Unitary matrix?', correct: 'A complex square matrix whose conjugate transpose is its inverse.', wrong: [['A matrix with only 1s', 'That is an all-ones matrix.', 'Generalizes orthogonal matrices to C.'], ['A matrix with determinant 1', 'That is the Special Linear group SL(n).', 'Unitary matrices preserve the inner product.'], ['An identity matrix', 'Identity is unitary, but not all unitary are identity.', 'U* U = I.']] },
      { id: 19227, chapter: 'Linear Algebra', title: 'Singular Value Decomposition', prompt: 'In SVD (A = USV^T), what are the entries of S?', correct: 'The square roots of the eigenvalues of A^T A (Singular Values).', wrong: [['The eigenvalues of A', 'A might not be square or diagonalizable.', 'Singular values are always non-negative.'], ['The trace of A', 'No.', 'U and V are orthogonal/unitary.'], ['Random numbers', 'No.', 'Provides the best low-rank approximation.']] },
      { id: 19149, chapter: 'Probability', title: 'Poisson Process', prompt: 'In a Poisson process with rate lambda, what is the distribution of time between events?', correct: 'Exponential with mean 1/lambda.', wrong: [['Poisson', 'Poisson is for the count of events in a window.', 'Time is continuous.'], ['Normal', 'Time is always positive and memoryless.', 'Memoryless property is unique to Exponential.'], ['Gamma', 'Gamma is the time until the n-th event.', 'Inter-arrival time is Exponential.']] },
      { id: 19150, chapter: 'Probability', title: 'Memoryless Property', prompt: 'Which continuous distribution has the property P(X > s+t | X > s) = P(X > t)?', correct: 'Exponential', wrong: [['Normal', 'Normal distribution depends on the absolute value of s.', 'Exponential only cares about the remaining time.'], ['Uniform', 'If you know you are past s, the remaining range is smaller.', 'Unique to Exponential in continuous time.'], ['Log-Normal', 'No.', 'Used for modeling time-to-failure.']] }
    ])
  }
}
